import React from "react";

import { BrowserRouter, Routes, Route } from "react-router-dom";

import Login from "./Containers/LoginScreen/Login";

import Dashboard from "./Containers/Dashboard/Dashboard";

import AddUser from "./Containers/Dashboard/UserManagement/Add";
import ViewUsers from "./Containers/Dashboard/UserManagement/View";
import EditMember from "./Containers/Dashboard/Member/EditMember";

import ViewMembers from "./Containers/Dashboard/Member/View";
import GenerateCard from "./Containers/Dashboard/Member/GenerateCard";
import SearchMember from "./Containers/Dashboard/Member/Search";
import AddMember from "./Containers/Dashboard/Member/AddMember";
import SpecialMembers from "./Containers/Dashboard/Member/SpecialMembers";

import MemberProfile from "./Containers/Dashboard/Member/MemberProfile";

import NotificationsToAll from "./Containers/Dashboard/Notification/All";
import SelectedUsers from "./Containers/Dashboard/Notification/SelectedUsers";

import FeedbackReceived from "./Containers/Dashboard/Feedback/Received";

import AccountProfile from "./Containers/Dashboard/Account/Profile";

import TwoFactorSetup from "./Containers/Dashboard/Account/2FA";

import ProtectedRoute from "./Components/ProtectedRoute/ProtectedRoute";

import AuthContext from "./context/auth";
import ThemeContext from "./context/theme";
import WhatsAppScreen from "./Containers/Dashboard/WhatsApp";

import BirthdayWishes from "./Containers/Dashboard/WhatsApp/BirthdayWishes";

function App() {
  let [authState, setAuthState] = React.useState({
    isLoggedIn: false,
    user: null,
    token: null,
  });

  let handleLogin = (user, token) => {
    localStorage.setItem("user", JSON.stringify(user));
    setAuthState({
      isLoggedIn: true,
      user: user,
      token: token,
    });
  };

  let handleLogout = () => {
    localStorage.removeItem("user");

    setAuthState({
      isLoggedIn: false,
      user: null,
      token: null,
    });
  };

  let local_user = localStorage.getItem("user");
  if (local_user && !authState["user"]) {
    let user_temp = JSON.parse(local_user);
    handleLogin(user_temp, user_temp["token"]);
  }

  let [theme, setTheme] = React.useState(localStorage.getItem("theme") || "light");

  React.useEffect(() => {
    localStorage.setItem("theme", theme);
  }, [theme]);

  function toggleTheme() {
    setTheme((prev) => (prev === "light" ? "dark" : "light"));
  }

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <AuthContext.Provider
        value={{
          isLoggedIn: authState.isLoggedIn,
          user: authState.user,
          token: authState.token,
          handleLogin: handleLogin,
          handleLogout: handleLogout,
        }}
      >
        <BrowserRouter>
          <Routes>
          <Route path="/" element={<Login />} />
          <Route
            path="/dashboard"
            element={
              <ProtectedRoute>
                <ViewMembers />
              </ProtectedRoute>
            }
          />
          <Route
            path="/dashboard/user/add"
            element={
              <ProtectedRoute>
                <AddUser />
              </ProtectedRoute>
            }
          />
          <Route
            path="/dashboard/user/view"
            element={
              <ProtectedRoute>
                <ViewUsers />
              </ProtectedRoute>
            }
          />
          <Route
            path="/dashboard/members/view"
            element={
              <ProtectedRoute>
                <ViewMembers />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/members/edit"
            element={
              <ProtectedRoute>
                <EditMember />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/members/idcard"
            element={
              <ProtectedRoute>
                <GenerateCard />
              </ProtectedRoute>
            }
          />
          <Route
            path="/dashboard/members/search"
            element={
              <ProtectedRoute>
                <SearchMember />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/members/profile"
            element={
              <ProtectedRoute>
                <MemberProfile />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/members/add"
            element={
              <ProtectedRoute>
                <AddMember />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/members/special"
            element={
              <ProtectedRoute>
                <SpecialMembers />
              </ProtectedRoute>
            }
          />
          <Route
            path="/dashboard/notification/all"
            element={
              <ProtectedRoute>
                <NotificationsToAll />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/notification/selected"
            element={
              <ProtectedRoute>
                <SelectedUsers />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/feedback/all"
            element={
              <ProtectedRoute>
                <FeedbackReceived />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/account/profile"
            element={
              <ProtectedRoute>
                <AccountProfile />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/account/2FA"
            element={
              <ProtectedRoute>
                <TwoFactorSetup />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/whatsapp/"
            element={
              <ProtectedRoute>
                <WhatsAppScreen />
              </ProtectedRoute>
            }
          />

          <Route
            path="/dashboard/whatsapp/birthday"
            element={
              <ProtectedRoute>
                <BirthdayWishes />
              </ProtectedRoute>
            }
          />
          </Routes>
        </BrowserRouter>
      </AuthContext.Provider>
    </ThemeContext.Provider>
  );
}

export default App;
