import React, { useEffect, useRef } from "react";

import { Modal } from "react-bootstrap";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import {
  Button,
  Container,
  Spinner,
  Row,
  Col,
  Alert,
  Form,
} from "react-bootstrap";

import { socket } from "../../../utils/socket";

import QRCode from "react-qr-code";

import RecepientSelector from "./SelectRecepient";

export default function WhatsAppScreen() {
  const [status, setStatus] = React.useState("DISCONNECTED");
  const [qrData, setQRData] = React.useState(null);

  const getWhatsAppQRCode = () => {
    socket.emit("generateQR");
    setStatus("REQUESTED");
  };

  useEffect(() => {
    socket.on("QRGenerated", (qr) => {
      console.log(qr);
      if (status !== "CONNECTED") {
        setStatus("GENERATED");
        setQRData(qr);
      }
    });

    socket.on("loadSuccess", () => {
      setStatus("CONNECTED");
    });

    socket.on("meesageResult", (data) => {
      alert("MESSAGE DELIVERED ON WHATSAPP");
      console.log(JSON.parse(data));
    });
  }, []);

  // 3 stages  // DISCONNECTED // //PENDING //CONNECTED

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Messaging</div>
              <h1 className={styles.title}>WhatsApp Web</h1>
              <p className={styles.subtext}>
                Connect WhatsApp Web, scan the QR code, then send polished bulk messages from one place.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>Status: {status}</span>
              <span className={styles.metaPill}>Bulk messaging</span>
            </div>
          </div>
        </section>

        <Container fluid className="p-0">
          <div className={styles.panel}>
            <div className={styles.panelHeader}>Connection and delivery</div>
            <div className={styles.panelBody}>
              <CurrentStatus
                status={status}
                getWhatsAppQRCode={getWhatsAppQRCode}
                qrData={qrData}
                setStatus={setStatus}
              />
            </div>
          </div>
        </Container>
      </div>
    </Template>
  );
}

function CurrentStatus({ status, getWhatsAppQRCode, qrData, setStatus }) {
  switch (status) {
    case "DISCONNECTED":
      return (
        <div className={styles.stack}>
          <div className={styles.softNote}>
            Current status: <span className="fw-semibold text-danger">Disconnected</span>
          </div>
          <div>
            <Button
              onClick={() => {
                getWhatsAppQRCode();
              }}
              variant="dark"
            >
              Initialize WhatsApp Web
            </Button>
          </div>
        </div>
      );

    case "REQUESTED":
      return (
        <div className={styles.stack}>
          <div className={styles.softNote}>
            Current status: <span className="fw-semibold text-warning">QR requested</span>
          </div>
          <Spinner animation="border" />
        </div>
      );

    case "GENERATED":
      return (
        <Row className="g-3 align-items-center">
          <Col md="4" className="text-center">
            <div className={styles.previewBox}>
              <QRCode value={qrData} />
            </div>
          </Col>
          <Col md="8">
            <Alert variant="success" className="mb-0">
              Scan the QR code in your WhatsApp application to activate the connection.
            </Alert>
          </Col>
        </Row>
      );

    case "CONNECTED":
      return (
        <div className={styles.stack}>
          <div className={styles.softNote}>
            Current status: <span className="fw-semibold text-success">WhatsApp connected</span>
          </div>
          <div>
            <Button
              variant="dark"
              onClick={() => {
                socket.emit("logout");
                setStatus("DISCONNECTED");
              }}
            >
              Disconnect WhatsApp Web
            </Button>
          </div>
          <hr className="my-2" />
          <div>
            <SendMessage />
          </div>
        </div>
      );
  }
}

function SendMessage() {
  const [modalOpen, setmodalOpen] = React.useState(false);
  const [messageData, setMessageData] = React.useState({
    numbers: [],
    message: "",
  });

  function sendMessage() {
    console.log(messageData);
    socket.emit("sendMessage", JSON.stringify(messageData));
  }

  return (
    <div className="py-2">
      <div className="d-flex justify-content-end mb-3">
        <Button
          variant="secondary"
          onClick={() => {
            setmodalOpen(true);
          }}
        >
          Choose recipients
        </Button>
      </div>

      <Modal
        fullscreen={true}
        show={modalOpen}
        onEscapeKeyDown={() => {
          setmodalOpen(false);
        }}
      >
        <Modal.Header>Select recipients</Modal.Header>
        <Modal.Body>
          <RecepientSelector
            setRecepients={(selectedNums) => {
              setMessageData({
                ...messageData,
                numbers: [...selectedNums],
              });
            }}
            closeModal={() => {
              setmodalOpen(false);
            }}
          />
        </Modal.Body>
      </Modal>
      <Form>
        <Form.Group>
          <Form.Label>Recipients numbers</Form.Label>
          <Form.Control value={messageData.numbers.join()} readOnly />
        </Form.Group>

        <Form.Group className="mt-3">
          <Form.Label>WhatsApp message</Form.Label>
          <Form.Control
            as="textarea"
            rows={6}
            value={messageData.message}
            onChange={(e) => {
              setMessageData({
                ...messageData,
                message: e.target.value,
              });
            }}
          />
        </Form.Group>
      </Form>

      <div className="mt-3">
        <Button
          variant="dark"
          onClick={() => {
            sendMessage();
          }}
        >
          Send message
        </Button>
      </div>
    </div>
  );
}
