import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Alert, Form, Button, Table } from "react-bootstrap";

import AuthContext from "../../../context/auth";

import { useFormik } from "formik";

import * as Yup from "yup";
import { BACKEND } from "../../../CONSTANTS";

export default function Profile() {
  const authContext = React.useContext(AuthContext);

  const initialValues = {
    existingPassword: "",
    newPassword: "",
    confirmPassword: "",
  };

  const validationSchema = Yup.object({
    existingPassword: Yup.string().required(),
    newPassword: Yup.string().required(),
    confirmPassword: Yup.string()
      .oneOf([Yup.ref("newPassword")], "Passwords do not match")
      .required(),
  });

  async function handlePasswordChange(values) {
    try {
      console.log(values);
      let res = await fetch(
        BACKEND +
          "/dashboard/user/changePassword/" +
          authContext["user"]["phone"],
        {
          method: "POST",
          headers: new Headers({
            "Content-Type": "application/json",
            "x-auth-token": authContext["token"],
          }),
          body: JSON.stringify(values),
        }
      );

      if (res.ok) {
        alert("PASSWORD CHANGED SUCCESSFULLY");
        formik.resetForm();
      } else {
        alert("ERROR: " + (await res.text()));
      }
    } catch (error) {
      alert("C ERROR: " + error.message);
    }
  }

  const formik = useFormik({
    initialValues,
    validationSchema,
    onSubmit: handlePasswordChange,
  });

  function gen2FAStatus() {
    let status = authContext.user["2FA_enabled"];
    if (status) {
      return (
        <span style={{ color: "green", fontWeight: "bold" }}>ACTIVATED</span>
      );
    } else
      return (
        <span style={{ color: "red", fontWeight: "bold" }}>NOT ACTIVE</span>
      );
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Account settings</div>
              <h1 className={styles.title}>User Profile</h1>
              <p className={styles.subtext}>
                Review your account details and update your password from a clean, mobile-friendly layout.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>{authContext?.user?.assigned_role}</span>
              <span className={styles.metaPill}>{authContext?.user?.phone}</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>User details</Card.Header>
          <Card.Body className={styles.panelBody}>
            <div className={styles.kvGrid}>
              {[
                ["Name", authContext.user.name],
                ["Assigned Role", authContext.user.assigned_role],
                ["Email Address", authContext.user.email],
                ["Phone", authContext.user.phone],
                ["Assigned Constituency", authContext.user.constituency],
                ["Assigned Ward", authContext.user.ward],
                ["Registered on", new Date(authContext.user.registered_on).toDateString()],
                ["Two Factor Authentication", gen2FAStatus()],
              ].map(([label, value]) => (
                <div key={label} className={styles.kvItem}>
                  <span className={styles.kvLabel}>{label}</span>
                  <span className={styles.kvValue}>{value}</span>
                </div>
              ))}
            </div>
          </Card.Body>
        </Card>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Change password</Card.Header>
          <Card.Body className={styles.panelBody}>
            <Form>
              <Row className="g-3">
                <Form.Group as={Col} md="4">
                  <Form.Label>Existing Password</Form.Label>
                  <Form.Control
                    name="existingPassword"
                    {...formik.getFieldProps("existingPassword")}
                  />
                </Form.Group>

                <Form.Group as={Col} md="4">
                  <Form.Label>New Password</Form.Label>
                  <Form.Control
                    name="newPassword"
                    {...formik.getFieldProps("newPassword")}
                  />
                </Form.Group>

                <Form.Group as={Col} md="4">
                  <Form.Label>Confirm Password</Form.Label>
                  <Form.Control
                    name="confirmPassword"
                    {...formik.getFieldProps("confirmPassword")}
                  />
                </Form.Group>

                <Col xs="12" className="d-flex justify-content-end">
                  <Button
                    disabled={!formik.isValid || !formik.dirty}
                    variant="dark"
                    onClick={formik.handleSubmit}
                  >
                    Change Password
                  </Button>
                </Col>
              </Row>
            </Form>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
