import React from "react";
import styles from "./Style.module.css";
import Navigation from "./Navigation";
import AuthContext from "../../context/auth";
import ThemeContext from "../../context/theme";
import { FiMenu, FiX, FiSun, FiMoon } from "react-icons/fi";

export default function Template({ children }) {
  const [sidebarOpen, setSidebarOpen] = React.useState(false);
  const authContext = React.useContext(AuthContext);
  const { theme, toggleTheme } = React.useContext(ThemeContext);

  const userInitial = authContext?.user?.name?.charAt(0)?.toUpperCase() || "A";
  const userName = authContext?.user?.name || "Admin";
  const userRole = authContext?.user?.assigned_role || "";

  return (
    <div className={`${styles.root} ${theme === "dark" ? styles.dark : styles.light}`}>
      {/* Mobile overlay */}
      {sidebarOpen && (
        <div
          className={styles.overlay}
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`${styles.sidebar} ${sidebarOpen ? styles.sidebarOpen : ""}`}>
        <Navigation onClose={() => setSidebarOpen(false)} />
      </aside>

      {/* Main area */}
      <div className={styles.main}>
        {/* Top bar */}
        <header className={styles.topbar}>
          <button
            className={styles.menuBtn}
            onClick={() => setSidebarOpen(!sidebarOpen)}
            aria-label="Toggle menu"
          >
            {sidebarOpen ? <FiX size={20} /> : <FiMenu size={20} />}
          </button>

          <div className={styles.topbarBrand}>
            <span className={styles.topbarTitle}>Sheikh Imran</span>
            <span className={styles.topbarSub}>Management Dashboard</span>
          </div>

          <div className={styles.topbarUser}>
            <button
              className={styles.themeBtn}
              onClick={toggleTheme}
              aria-label="Toggle color theme"
              title={`Switch to ${theme === "light" ? "dark" : "light"} mode`}
            >
              {theme === "light" ? <FiMoon size={16} /> : <FiSun size={16} />}
            </button>
            <span className={styles.userBadge}>{userInitial}</span>
            <div className={styles.userInfo}>
              <span className={styles.userName}>{userName}</span>
              {userRole && <span className={styles.userRole}>{userRole}</span>}
            </div>
          </div>
        </header>

        {/* Page content */}
        <main className={styles.content}>
          {children}
        </main>
      </div>
    </div>
  );
}
