import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import AuthContext from "../../context/auth";
import { BACKEND } from "../../CONSTANTS";
import LOGO from "../../assets/logo.png";
import styles from "./Navigation.module.css";
import {
  FiLayers,
  FiUsers, FiUserPlus, FiCreditCard, FiSearch, FiStar, FiGift,
  FiMessageCircle, FiDownload, FiBell, FiMessageSquare,
  FiUser, FiLock, FiLogOut, FiChevronRight,
} from "react-icons/fi";

function NavGroup({ label, children, icon: Icon, defaultOpen = false }) {
  const [open, setOpen] = React.useState(defaultOpen);
  return (
    <div className={styles.group}>
      <button className={styles.groupHeader} onClick={() => setOpen(!open)}>
        <span className={styles.groupLabel}>
          {Icon ? <Icon size={12} className={styles.groupHeaderIcon} /> : null}
          <span>{label}</span>
        </span>
        <FiChevronRight
          size={12}
          className={`${styles.chevron} ${open ? styles.chevronOpen : ""}`}
        />
      </button>
      {open && <div className={styles.groupItems}>{children}</div>}
    </div>
  );
}

function NavItem({ icon: Icon, label, onClick, active = false }) {
  return (
    <button className={`${styles.navItem} ${active ? styles.navItemActive : ""}`} onClick={onClick}>
      {Icon && <Icon size={14} className={styles.navIcon} />}
      <span>{label}</span>
    </button>
  );
}

function NavDownload({ label, href }) {
  return (
    <a
      className={styles.navItem}
      href={href}
      target="_blank"
      rel="noreferrer"
    >
      <FiDownload size={14} className={styles.navIcon} />
      <span>{label}</span>
    </a>
  );
}

export default function Navigation({ onClose }) {
  const Navigator = useNavigate();
  const location = useLocation();
  const authContext = React.useContext(AuthContext);

  function go(path) {
    Navigator(path);
    if (onClose) onClose();
  }

  function isRouteActive(path, exact = false) {
    if (exact) return location.pathname === path;
    return location.pathname.startsWith(path);
  }

  const isSuperUser = authContext?.user?.assigned_role === "SUPER USER";

  return (
    <div className={styles.wrapper}>
      {/* Logo */}
      <div className={styles.logoArea}>
        <img src={LOGO} alt="logo" className={styles.logoImg} />
        <div className={styles.brandMeta}>
          <div className={styles.logoName}>Sheikh Imran</div>
          <div className={styles.logoSub}>Admin Panel</div>
        </div>
      </div>

      <div className={styles.userTag}>
        <span className={styles.userRolePill}>{authContext?.user?.assigned_role || "USER"}</span>
      </div>

      {/* Nav sections */}
      <nav className={styles.nav}>
        <NavGroup label="Member Management" icon={FiLayers} defaultOpen={true}>
          <NavItem icon={FiUsers} label="All Members" active={isRouteActive("/dashboard/members/view", true)} onClick={() => go("/dashboard/members/view")} />
          <NavItem icon={FiStar} label="Special Status Members" active={isRouteActive("/dashboard/members/special", true)} onClick={() => go("/dashboard/members/special")} />
          <NavItem icon={FiCreditCard} label="Generate ID Card" active={isRouteActive("/dashboard/members/idcard", true)} onClick={() => go("/dashboard/members/idcard")} />
          <NavItem icon={FiSearch} label="Search Member" active={isRouteActive("/dashboard/members/search", true)} onClick={() => go("/dashboard/members/search")} />
          <NavItem icon={FiUserPlus} label="Add a Member" active={isRouteActive("/dashboard/members/add", true)} onClick={() => go("/dashboard/members/add")} />
          <NavItem icon={FiGift} label="Birthday Wishes" active={isRouteActive("/dashboard/whatsapp/birthday", true)} onClick={() => go("/dashboard/whatsapp/birthday")} />
          <NavItem icon={FiMessageCircle} label="WhatsApp Blast" active={isRouteActive("/dashboard/whatsapp", true)} onClick={() => go("/dashboard/whatsapp")} />
          <NavDownload label="Download Report" href={BACKEND + "/dashboard/reports/members"} />
        </NavGroup>

        <div className={styles.divider} />

        {isSuperUser && (
          <>
            <NavGroup label="User Management" icon={FiUsers}>
              <NavItem icon={FiUsers} label="Existing Users" active={isRouteActive("/dashboard/user/view", true)} onClick={() => go("/dashboard/user/view")} />
              <NavItem icon={FiUserPlus} label="Add a New User" active={isRouteActive("/dashboard/user/add", true)} onClick={() => go("/dashboard/user/add")} />
              <NavDownload label="Download Report" href={BACKEND + "/dashboard/reports/users"} />
            </NavGroup>
            <div className={styles.divider} />
            <NavGroup label="Notifications" icon={FiBell}>
              <NavItem icon={FiBell} label="Notify All Users" active={isRouteActive("/dashboard/notification/all", true)} onClick={() => go("/dashboard/notification/all")} />
            </NavGroup>
            <div className={styles.divider} />
          </>
        )}

        <NavGroup label="Feedback" icon={FiMessageSquare}>
          <NavItem icon={FiMessageSquare} label="View Received Feedback" active={isRouteActive("/dashboard/feedback/all", true)} onClick={() => go("/dashboard/feedback/all")} />
          <NavDownload label="Download Report" href={BACKEND + "/dashboard/reports/feedback"} />
        </NavGroup>

        <div className={styles.divider} />

        <NavGroup label="Account" icon={FiUser}>
          <NavItem icon={FiUser} label="My Profile" active={isRouteActive("/dashboard/account/profile", true)} onClick={() => go("/dashboard/account/profile")} />
          <NavItem icon={FiLock} label="Setup 2FA" active={isRouteActive("/dashboard/account/2FA", true)} onClick={() => go("/dashboard/account/2FA")} />
        </NavGroup>
      </nav>

      {/* Footer logout */}
      <div className={styles.footer}>
        <button
          className={styles.logoutBtn}
          onClick={() => {
            authContext.handleLogout();
            Navigator("/");
          }}
        >
          <FiLogOut size={14} />
          <span>Sign Out</span>
        </button>
      </div>
    </div>
  );
}
