import { BACKEND } from "../../../CONSTANTS";
import { useLocation } from "react-router-dom";
import {
  FiCalendar,
  FiFlag,
  FiGrid,
  FiHome,
  FiImage,
  FiMail,
  FiMapPin,
  FiMessageCircle,
  FiPhone,
  FiUser,
  FiUsers,
} from "react-icons/fi";

import AuthContext from "../../../context/auth";
import styles from "./EditMember.module.css";

function convertDateIntoCalendar(val){

    let date = val === null ? new Date() : new Date(val);
   
    var getYear = date.toLocaleString("default", { year: "numeric" });
    var getMonth = date.toLocaleString("default", { month: "2-digit" });
    var getDay = date.toLocaleString("default", { day: "2-digit" });
    var dateFormat = getYear + "-" + getMonth + "-" + getDay;
    return dateFormat
}

const MAX_IMAGE_BYTES = 1024 * 1024;

function createImage(src) {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.addEventListener("load", () => resolve(image));
    image.addEventListener("error", (error) => reject(error));
    image.setAttribute("crossOrigin", "anonymous");
    image.src = src;
  });
}

async function getCroppedImageBlob(imageSrc, pixelCrop) {
  const image = await createImage(imageSrc);
  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");

  if (!context) {
    throw new Error("CANVAS_NOT_SUPPORTED");
  }

  canvas.width = pixelCrop.width;
  canvas.height = pixelCrop.height;

  context.drawImage(
    image,
    pixelCrop.x,
    pixelCrop.y,
    pixelCrop.width,
    pixelCrop.height,
    0,
    0,
    pixelCrop.width,
    pixelCrop.height
  );

  let quality = 0.92;

  while (quality >= 0.5) {
    // eslint-disable-next-line no-await-in-loop
    const blob = await new Promise((resolve) => {
      canvas.toBlob(
        (result) => resolve(result),
        "image/jpeg",
        quality
      );
    });

    if (blob && blob.size <= MAX_IMAGE_BYTES) {
      return blob;
    }

    quality -= 0.08;
  }

  throw new Error("CROPPED_IMAGE_TOO_LARGE");
}

export default function EditMember() {

  const authContext = React.useContext(AuthContext);
    const search = useLocation().search;
    const member_id = new URLSearchParams(search).get("id");


    let [toggle,setToggle] = React.useState(false)


  let [preview, setPreview] = React.useState(null);
  const previewRef = React.useRef(null);

  const [cropModalOpen, setCropModalOpen] = React.useState(false);
  const [cropSource, setCropSource] = React.useState(null);
  const [crop, setCrop] = React.useState({ x: 0, y: 0 });
  const [zoom, setZoom] = React.useState(1);
  const [croppedAreaPixels, setCroppedAreaPixels] = React.useState(null);

  let [LocationData, setLocationData] = React.useState(null);

  let [memberData,setMemberData] = React.useState({})

  async function getLocationData() {
    try {
      let res = await fetch(BACKEND + "/location");
      if (res.ok) {
        let DATA = await res.json();
        console.log(DATA);
        setLocationData(DATA);
      } else {
        alert("ERROR: ", await res.text());
      }
    } catch (error) {
      alert("CLIENT ERROR: ", error.message);
    }
  }

  function renderHalqaFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }

    if (LocationData?.HALQAS[constituency])
      return LocationData?.HALQAS[constituency];
    else return [];
  }

  function renderConstituencyFromDistrict(district) {
    if (!district) {
      return [];
    }
    if (LocationData?.CONSTITUENCIES[district]) {
      return LocationData?.CONSTITUENCIES[district];
    } else return [];
  }

  function renderWardsFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }
    if (LocationData?.WARDS[constituency]) {
      return LocationData?.WARDS[constituency];
    } else return [];
  }

  function renderBoothsFromHalqas(halqa) {
    if (!halqa) {
      return [];
    }

    if (LocationData?.BOOTHS[halqa]) {
      return LocationData?.BOOTHS[halqa];
    } else return [];
  }

  async function getDataFromServer() {
    try {
      let res = await fetch(
        BACKEND + "/dashboard/member/profile/" + member_id,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["user"]["token"],
          }),
        }
      );

      if (res.ok) {
        setMemberData(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  React.useEffect(() => {
    getLocationData();
  }, []);

  React.useEffect(() => {
    return () => {
      if (previewRef.current) {
        URL.revokeObjectURL(previewRef.current);
      }
      if (cropSource) {
        URL.revokeObjectURL(cropSource);
      }
    };
  }, [cropSource]);

  let initialValues = {
    name: "",
    parentage: "",
    phone: "",
    whatsapp: "",
    email: "",
    district: "",
    constituency: "",
    ward: "",
    halqa: "NA",
    mohalla: "",

   
    new_photo: null,
    ...memberData,
    dob: convertDateIntoCalendar(memberData["dob"]),
  };

  

  let validationSchema = Yup.object({
    name: Yup.string().required(),
    parentage: Yup.string().required(),
    phone: Yup.string().length(10).required(),
    whatsapp: Yup.string().length(10),
    email: Yup.string().email(),
    district: Yup.string().required(),
    constituency: Yup.string().required(),
    ward: Yup.string().required(),
    halqa: Yup.string().required(),
    mohalla: Yup.string().required(),
    dob: Yup.date().required(),
    new_photo: Yup.mixed()
    
  });

  let formik = useFormik({
    initialValues:initialValues,
    validationSchema,
    onSubmit: handleServerUpload,
    enableReinitialize:true
  });

  // console.log(formik.values);

  const convertToBase64 = (file) => {
    return new Promise((resolve, reject) => {
      const fileReader = new FileReader();
      fileReader.readAsDataURL(file);
      fileReader.onload = () => {
        resolve(fileReader.result);
      };
      fileReader.onerror = (error) => {
        reject(error);
      };
    });
  };

  async function handleServerUpload(values) {
    try {
      console.log(values);

      let IMG = null

      //If new photo is available / has been selected

      if(values["new_photo"]){
        let file = values["new_photo"]["name"];

      //file:///data/user/0/host.exp.exponent/cache/ExperienceData/%2540anonymous%252Fmobile-83b2ae8d-080a-4c6e-8950-c08074b9d820/Camera/ce4392f8-4846-40fc-b36b-c9858c3da762.jpg
      let extension = file.split(".");
      extension = extension[extension.length - 1];
      let filename = file;

      filename = filename.replace(" ", "-");
      filename = filename.replace("%", "_");

       IMG = {
        name: "photo",
        filename: `${filename}`,
        type: `image/${extension}`,
      };


      let tempIMG = await convertToBase64(values["new_photo"]);

      let base64Image = tempIMG.split(";base64,").pop();

      IMG["base64"] = base64Image;
      }

      const payloadValues = { ...values };
      delete payloadValues["new_photo"];

      let DATA = { ...payloadValues, IMG };

      console.log({
        DATA,
      });


 

      let res = await fetch(BACKEND + "/member/update", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
        }),
        body: JSON.stringify(DATA),
      });

      if (res.ok) {
        alert("MEMBER UPDATED SUCCESS");
        if (previewRef.current) {
          URL.revokeObjectURL(previewRef.current);
          previewRef.current = null;
        }
        setPreview(null);
        formik.resetForm();
        setToggle(!toggle)
      } else {
        alert("ERROR: " + (await res.text()));
      }
    } catch (error) {
      alert("CLIENT ERROR: " + error.message);
    }
  }

  function handleFileUpload(
    key,
    event,
    type = ["image/png", "image/jpeg", "image/jpg"]
  ) {
    console.log({ event });

    let file = event.target.files[0];

    if (!file) {
      console.log("CANCEL CLICKED");
      event.target.value = null;
      setPreview(null);
      formik.setFieldValue(key, "");
      return;
    }
    //CHECK FOR FILE TYPE

    let file_type_matches = false;

    for (let filetype of type) {
      console.log(filetype);
      if (file["type"] === filetype) {
        file_type_matches = true;
        break;
      }
    }

    if (!file_type_matches) {
      alert("Please upload specified format file");
      event.target.value = null;
      return;
    }

    if (file.size > 8 * 1024 * 1024) {
      alert("Selected image is too large. Please choose an image under 8MB before cropping.");
      event.target.value = null;
      return;
    }

    if (cropSource) {
      URL.revokeObjectURL(cropSource);
    }

    const sourceUrl = URL.createObjectURL(file);
    setCropSource(sourceUrl);
    setCrop({ x: 0, y: 0 });
    setZoom(1);
    setCroppedAreaPixels(null);
    setCropModalOpen(true);
    event.target.value = null;
    formik.setFieldValue(key, null);
  }

  async function applyCroppedImage() {
    try {
      if (!cropSource || !croppedAreaPixels) {
        throw new Error("Please adjust crop area first");
      }

      const croppedBlob = await getCroppedImageBlob(cropSource, croppedAreaPixels);

      if (!croppedBlob || croppedBlob.size > MAX_IMAGE_BYTES) {
        throw new Error("Final image must be 1MB or less");
      }

      const croppedFile = new File([croppedBlob], `member-${Date.now()}.jpg`, {
        type: "image/jpeg",
      });

      if (previewRef.current) {
        URL.revokeObjectURL(previewRef.current);
      }

      const previewUrl = URL.createObjectURL(croppedFile);
      previewRef.current = previewUrl;

      formik.setFieldValue("new_photo", croppedFile);
      setPreview(previewUrl);
      setCropModalOpen(false);
    } catch (error) {
      alert(error.message || "Unable to crop image");
    }
  }

  if (LocationData === null) {
    return (
      <Template>
        <div>Loading, please wait ...</div>
      </Template>
    );
  }

  return (
    <Template>
      <div className={styles.pageWrap}>
        <Card className={styles.formCard}>
          <Card.Header className={styles.formHeader}>
            <div>
              <h3 className={styles.heading}>Update Member Details</h3>
              <p className={styles.subheading}>Keep profile information accurate and card-ready.</p>
            </div>
          </Card.Header>
          <Card.Body>
          <Row className="g-3">
            <Form.Group md="5" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiUser /> Full Name</Form.Label>
              <Form.Control name="name" {...formik.getFieldProps("name")} />
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiUsers /> Parentage</Form.Label>
              <Form.Control
                name="parentage"
                {...formik.getFieldProps("parentage")}
              />
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiCalendar /> Date of Birth</Form.Label>
              <Form.Control
                type="date"
                name="dob"
                {...formik.getFieldProps("dob")}
              />
            </Form.Group>
          </Row>

          <Row>
            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiPhone /> Phone</Form.Label>
              <Form.Control name="phone" {...formik.getFieldProps("phone")} />
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiMessageCircle /> WhatsApp</Form.Label>
              <Form.Control
                name="whatsapp"
                {...formik.getFieldProps("whatsapp")}
              />
            </Form.Group>

            <Form.Group md="6" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiMail /> Email (Optional)</Form.Label>
              <Form.Control name="email" {...formik.getFieldProps("email")} />
            </Form.Group>
          </Row>

          <Row>
            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiMapPin /> District</Form.Label>
              <Form.Select
                name="district"
                {...formik.getFieldProps("district")}
              >
                <option value="">Please Choose</option>
                {LocationData?.DISTRICTS.map((district, index) => {
                  return <option key={district}>{district}</option>;
                })}
              </Form.Select>
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiFlag /> Constituency</Form.Label>
              <Form.Select
                name="constituency"
                {...formik.getFieldProps("constituency")}
              >
                <option value="">Please Choose</option>
                {renderConstituencyFromDistrict(formik.values["district"]).map(
                  (constituency, index) => {
                    return (
                      <option key={constituency} value={constituency}>
                        {constituency}
                      </option>
                    );
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiGrid /> Halqa</Form.Label>
              <Form.Select name="halqa" {...formik.getFieldProps("halqa")}>
                <option value="">Please Choose</option>
                {renderHalqaFromConstituency(formik.values["constituency"]).map(
                  (halqa, index) => {
                    return <option key={halqa}>{halqa}</option>;
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiGrid /> Ward</Form.Label>
              <Form.Select name="ward" {...formik.getFieldProps("ward")}>
                <option value="">Please Choose</option>
                {renderWardsFromConstituency(formik.values["constituency"]).map(
                  (ward, index) => {
                    return <option key={ward}>{ward}</option>;
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiHome /> Mohalla</Form.Label>
              <Form.Control
                name="mohalla"
                {...formik.getFieldProps("mohalla")}
              />
            </Form.Group>
          </Row>

          <Row>
            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label className={styles.labelWithIcon}><FiImage /> Member Photo</Form.Label>
              <Form.Control
                type="file"
                name="new_photo"
                accept="image/*"
                className={styles.fileInput}
                onChange={(e) => {
                  handleFileUpload("new_photo", e);
                }}
              />
              <div className={styles.fileHint}>Upload and crop image. Final size must be 1MB or less.</div>
            </Form.Group>

            <Form.Group md="5" as={Col} className="my-3">
              <div className={styles.previewPanel}>
                <div className={styles.previewLabel}>New Preview</div>
                {preview ? (
                  <img className={styles.previewImage} src={preview} alt="New member preview" />
                ) : (
                  <div className={styles.previewEmpty}>Choose image to preview</div>
                )}
              </div>
            </Form.Group>
          </Row>


          <Row>
            <div className="my-3">
              <Button
                disabled={!formik.dirty || !formik.isValid}
                variant={"success"}
                onClick={formik.handleSubmit}
              >
                UPDATE MEMBER DETAILS
              </Button>
            </div>
          </Row>
          </Card.Body>
        </Card>
      </div>

      <Modal
        show={cropModalOpen}
        onHide={() => setCropModalOpen(false)}
        centered
        size="lg"
      >
        <Modal.Header closeButton>
          <Modal.Title>Crop Member Photo</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <div className={styles.cropperWrap}>
            {cropSource && (
              <Cropper
                image={cropSource}
                crop={crop}
                zoom={zoom}
                aspect={1}
                onCropChange={setCrop}
                onZoomChange={setZoom}
                onCropComplete={(_, pixels) => setCroppedAreaPixels(pixels)}
              />
            )}
          </div>
          <div className={styles.zoomRow}>
            <span>Zoom</span>
            <Form.Range
              min={1}
              max={3}
              step={0.1}
              value={zoom}
              onChange={(e) => setZoom(Number(e.target.value))}
            />
          </div>
          <div className={styles.fileHint}>Final exported image will be compressed to max 1MB.</div>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setCropModalOpen(false)}>
            Cancel
          </Button>
          <Button variant="primary" onClick={applyCroppedImage}>
            Apply Crop
          </Button>
        </Modal.Footer>
      </Modal>
    </Template>
  );
}
