import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import {
  Row,
  Col,
  Card,
  Alert,
  Form,
  Button,
  Table,
  Spinner,
} from "react-bootstrap";

import AuthContext from "../../../context/auth";
import { BACKEND } from "../../../CONSTANTS";

import { Navigate, useNavigate } from "react-router-dom";

export default function TwoFactorSetup() {
  let [qrCode, setQRcode] = React.useState(null);

  const authContext = React.useContext(AuthContext);

  async function getQRCODE() {
    try {
      let res = await fetch(
        BACKEND + "/2FA/generateSecret/" + authContext["user"]["phone"],
        {
          method: "POST",
        }
      );

      if (res.ok) {
        let data = await res.text();
        setQRcode(data);
      } else alert("ERROR: " + (await res.text()));
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  async function activate2FA() {
    try {
      let res = await fetch(
        BACKEND + "/2FA/set2FAState/" + authContext["user"]["phone"],
        {
          method: "POST",
        }
      );

      if (res.ok) {
        alert("TWO FACTOR HAS BEEN ACTIVATED. PLEASE LOGIN AGAIN WITH TOKEN");
        Navigate("/");
        authContext.handleLogout();
      } else alert("ERROR: " + (await res.text()));
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getQRCODE();
  }, []);

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Security</div>
              <h1 className={styles.title}>Two Factor Authentication</h1>
              <p className={styles.subtext}>
                Protect this account with Google Authenticator and a second verification step at login.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>{authContext?.user?.phone}</span>
              <span className={styles.metaPill}>{authContext?.user?.["2FA_enabled"] ? "Enabled" : "Not active"}</span>
            </div>
          </div>
        </section>

        <Row className="g-3">
          <Col md="6">
            <Card className={styles.panel}>
              <Card.Header className={styles.panelHeader}>Step 1 - Scan QR code</Card.Header>
              <Card.Body className={styles.panelBody}>
                <div className="text-center py-3">
                  {qrCode ? (
                    <img src={qrCode} alt="qr" style={{ maxWidth: "100%" }} />
                  ) : (
                    <Spinner animation="border" />
                  )}
                </div>
                <ul className="mb-0 text-secondary">
                  <li>Install Google Authenticator from the Play Store.</li>
                  <li>Open the app and scan the QR code above.</li>
                  <li>Keep the generated token ready for the next step.</li>
                </ul>
              </Card.Body>
            </Card>
          </Col>

          <Col md="6">
            <Card className={styles.panel}>
              <Card.Header className={styles.panelHeader}>Step 2 - Activate 2FA</Card.Header>
              <Card.Body className={styles.panelBody}>
                <Alert variant="warning">
                  Make sure the QR code has been scanned before enabling 2FA.
                </Alert>
                <Alert variant="danger">
                  You will need the generated token on the next login.
                </Alert>

                <div className="d-flex justify-content-center">
                  {authContext["user"]?.["2FA_enabled"] ? (
                    <div className="fw-semibold text-success">Two factor authentication is already active.</div>
                  ) : (
                    <Button
                      variant="dark"
                      onClick={async () => {
                        await activate2FA();
                      }}
                    >
                      Activate 2FA
                    </Button>
                  )}
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </div>
    </Template>
  );
}
