import React from "react";
import styles from "./Login.module.css";
import LOGO from "../../assets/logo.png";
import { BACKEND } from "../../CONSTANTS";
import AuthContext from "../../context/auth";
import { useNavigate } from "react-router-dom";
import { FiPhone, FiLock, FiKey, FiLogIn } from "react-icons/fi";

export default function Login() {
  const NAVIGATE = useNavigate();
  const authContext = React.useContext(AuthContext);

  const [TFAUsed, setTFAUsed] = React.useState(false);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState("");
  const [credentials, setCredentials] = React.useState({
    phone: "",
    password: "",
    tfa_token: "",
  });

  async function sendDataToServer() {
    if (!credentials.phone || !credentials.password) {
      setError("Please enter your phone number and password.");
      return;
    }
    setError("");
    setLoading(true);
    try {
      let res = await fetch(BACKEND + "/dashboard/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...credentials, TFAUsed }),
      });
      if (res.ok) {
        let data = await res.json();
        authContext.handleLogin(data, data.token);
        NAVIGATE("/dashboard");
      } else {
        setError(await res.text());
      }
    } catch (err) {
      setError("Connection failed. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  function handleKeyDown(e) {
    if (e.key === "Enter") sendDataToServer();
  }

  return (
    <div className={styles.page}>
      <div className={styles.card}>
        <div className={styles.brand}>
          <img src={LOGO} alt="logo" className={styles.logo} />
          <h1 className={styles.brandName}>Sheikh Imran</h1>
          <p className={styles.brandTagline}>Management Dashboard</p>
        </div>

        <div className={styles.form}>
          <h2 className={styles.formTitle}>Welcome back</h2>
          <p className={styles.formSub}>Sign in to continue</p>

          {error && <div className={styles.errorBox}>{error}</div>}

          <div className={styles.field}>
            <label className={styles.label}>Phone Number</label>
            <div className={styles.inputWrap}>
              <FiPhone className={styles.inputIcon} />
              <input
                className={styles.input}
                type="tel"
                placeholder="10-digit phone number"
                value={credentials.phone}
                onChange={(e) => setCredentials({ ...credentials, phone: e.target.value })}
                onKeyDown={handleKeyDown}
              />
            </div>
          </div>

          <div className={styles.field}>
            <label className={styles.label}>Password</label>
            <div className={styles.inputWrap}>
              <FiLock className={styles.inputIcon} />
              <input
                className={styles.input}
                type="password"
                placeholder="Your password"
                value={credentials.password}
                onChange={(e) => setCredentials({ ...credentials, password: e.target.value })}
                onKeyDown={handleKeyDown}
              />
            </div>
          </div>

          <div className={styles.checkRow}>
            <label className={styles.checkLabel}>
              <input
                type="checkbox"
                className={styles.checkbox}
                checked={TFAUsed}
                onChange={() => setTFAUsed(!TFAUsed)}
              />
              Use 2FA token
            </label>
          </div>

          {TFAUsed && (
            <div className={styles.field}>
              <label className={styles.label}>2FA Token</label>
              <div className={styles.inputWrap}>
                <FiKey className={styles.inputIcon} />
                <input
                  className={styles.input}
                  type="text"
                  placeholder="Authenticator code"
                  value={credentials.tfa_token}
                  onChange={(e) => setCredentials({ ...credentials, tfa_token: e.target.value })}
                  onKeyDown={handleKeyDown}
                />
              </div>
            </div>
          )}

          <button
            className={styles.btn}
            onClick={sendDataToServer}
            disabled={loading}
          >
            {loading ? (
              <span className={styles.spinner} />
            ) : (
              <><FiLogIn /> Sign In</>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}
