import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Alert, Form, Button, Table } from "react-bootstrap";
import { BACKEND } from "../../../CONSTANTS";
import AuthContext from "../../../context/auth";

export default function NotificationsToAll() {
  const authContext = React.useContext(AuthContext);

  let [details, setDetails] = React.useState({
    image_url: "",
    title: "",
    message: "",
    feed_url: "",
    type: "message",
  });

  async function sendDataToServer() {
    try {
      let isValid = true;

      let requiredFields = [];

      if (details["type"] === "message") {
        requiredFields = ["image_url", "message", "title"];
      } else {
        requiredFields = ["feed_url", "title"];
      }

      requiredFields.forEach((field) => {
        if (details[field] === "") {
          isValid = false;
        }
      });

      if (!isValid) {
        alert("ENSURE ALL FIELDS ARE FILLED");
        return;
      }

      let res = await fetch(BACKEND + "/dashboard/notification/all", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
          "x-auth-token": authContext["token"],
        }),
        body: JSON.stringify(details),
      });

      if (res.ok) {
        alert("MESSAGE DELIVERED");
      }
    } catch (err) {
      alert("CLIENT ERROR: " + err.messsage);
    }
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Notifications</div>
              <h1 className={styles.title}>Notify All Users</h1>
              <p className={styles.subtext}>
                Send a polished broadcast announcement to all active app users.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>Global broadcast</span>
              <span className={styles.metaPill}>30 min batching rule</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Compose notification</Card.Header>
          <Card.Body className={styles.panelBody}>
            <Alert variant="warning" className="mb-4">
              Use this screen to notify all installed app users. Leave a 30 minute gap between batches.
            </Alert>

            <Form>
              <Row className="g-3">
                <Col xs="12">
                  <div className={styles.softNote}>Choose the notification format</div>
                  <div className="d-flex gap-3 flex-wrap mt-2">
                    <Form.Check
                      inline
                      label="Message with Image"
                      name="group1"
                      type={"radio"}
                      id={"message"}
                      checked={details["type"] === "message"}
                      onChange={() => setDetails({ ...details, type: "message" })}
                    />
                    <Form.Check
                      inline
                      label="Live Feed / Video Link"
                      name="group1"
                      type={"radio"}
                      id={"feed"}
                      checked={details["type"] === "link"}
                      onChange={() => setDetails({ ...details, type: "link" })}
                    />
                  </div>
                </Col>

                <Col md="6">
                  <Form.Group>
                    <Form.Label>{details["type"] === "message" ? "Image URL to attach" : "Video / link URL"}</Form.Label>
                    <Form.Control
                      value={details[details["type"] === "message" ? "image_url" : "feed_url"]}
                      onChange={(e) => {
                        const key = details["type"] === "message" ? "image_url" : "feed_url";
                        setDetails({ ...details, [key]: e.target.value });
                      }}
                    />
                  </Form.Group>
                </Col>

                <Col md="6">
                  <Form.Group>
                    <Form.Label>Title</Form.Label>
                    <Form.Control
                      value={details["title"]}
                      onChange={(e) => setDetails({ ...details, title: e.target.value })}
                    />
                  </Form.Group>
                </Col>

                {details["type"] === "message" && (
                  <Col xs="12">
                    <Form.Group>
                      <Form.Label>Message Content</Form.Label>
                      <Form.Control
                        as="textarea"
                        rows={8}
                        value={details["message"]}
                        onChange={(e) => setDetails({ ...details, message: e.target.value })}
                      />
                    </Form.Group>
                  </Col>
                )}

                <Col xs="12" className="d-flex justify-content-end">
                  <Button variant="dark" onClick={sendDataToServer}>
                    Notify All Users
                  </Button>
                </Col>
              </Row>
            </Form>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
