import React from "react";
import styles from "../../../../Components/PageTemplate/DashboardScreen.module.css";

import {
  Container,
  Row,
  Col,
  Table,
  Card,
  Button,
  Form,
} from "react-bootstrap";

import BootstrapSwitchButton from "bootstrap-switch-button-react";

import { BACKEND } from "../../../../CONSTANTS";

import { useNavigate } from "react-router-dom";
import AuthContext from "../../../../context/auth";

import useLocation from "../../../../hooks/useLocation";

export default function SelectRecepients({ setRecepients, closeModal }) {
  const [selectedMembers, setSelectedMembers] = React.useState([]);

  const {
    LocationData,
    renderConstituencyFromDistrict,
    renderHalqaFromConstituency,
    renderWardsFromConstituency,
  } = useLocation();

  const authContext = React.useContext(AuthContext);
  let [members, setMembers] = React.useState(null);
  let [toggle, setToggle] = React.useState(false);
  let [allSelected, setAllSelected] = React.useState(false);
  let [filter, setFilter] = React.useState({
    constituency: "",
    halqa: "",
    ward: "",
    filter_by: "NONE",
  });

  async function getDataFromServer() {
    try {
      console.log(filter);
      let res = await fetch(BACKEND + "/dashboard/member/view", {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["user"]["token"],
          "Content-Type": "application/json",
        }),
        body: JSON.stringify(filter),
      });

      if (res.ok) {
        setMembers(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  function renderTable() {
    if (members === null) {
      return <span>Loading Data, Please Wait ....</span>;
    }

    let temp = members.map((member, index) => {
      return (
        <tr key={member["member_id"]}>
          <td>
            {" "}
            <input
              type="checkbox"
              checked={selectedMembers.includes(member["phone"])}
              onChange={() => {
                if (selectedMembers.includes(member["phone"])) {
                  //already present remove through filter

                  let data = selectedMembers.filter((item) => {
                    return item !== member["phone"];
                  });

                  setSelectedMembers([...data]);
                } else {
                  //push

                  setSelectedMembers([...selectedMembers, member["phone"]]);
                }
              }}
            />{" "}
          </td>
          <td>{index + 1}</td>
          <td>{member["name"]}</td>
          <td>{member["parentage"]}</td>
          <td>{member["district"]}</td>
          <td>{member["constituency"]}</td>
          <td>{member["halqa"]}</td>
          <td>{member["ward"]}</td>
          <td>{member["phone"]}</td>
        </tr>
      );
    });

    return temp;
  }

  return (
    <>
      <Card>
        <Card.Header>FILTER MEMBER DATA</Card.Header>
        <Card.Body>
          <Row>
            <Col md="2">
              <Form.Label>CONSTITUENCY</Form.Label>
              <Form.Select
                value={filter.constituency}
                onChange={(e) => {
                  setFilter({
                    ...filter,
                    constituency: e.target.value,
                  });
                }}
              >
                <option value="">Please Choose</option>
                {renderConstituencyFromDistrict("SRINAGAR").map((i) => {
                  return <option value={i}>{i}</option>;
                })}
              </Form.Select>
            </Col>

            <Col md="2">
              <Form.Label>HALQA</Form.Label>
              <Form.Select
                value={filter.halqa}
                onChange={(e) => {
                  setFilter({
                    ...filter,
                    halqa: e.target.value,
                  });
                }}
              >
                <option value="">Please Choose</option>
                {renderHalqaFromConstituency(filter.constituency).map((i) => {
                  return <option value={i}>{i}</option>;
                })}
              </Form.Select>
            </Col>
            <Col md="2">
              <Form.Label>WARD</Form.Label>
              <Form.Select
                value={filter.ward}
                onChange={(e) => {
                  setFilter({
                    ...filter,
                    ward: e.target.value,
                  });
                }}
              >
                <option value="">Please Choose</option>
                {renderWardsFromConstituency(filter.constituency).map((i) => {
                  return <option value={i}>{i}</option>;
                })}
              </Form.Select>
            </Col>

            <Col md="2">
              <Form.Label>FILTER BY</Form.Label>
              <Form.Select
                value={filter.filter_by}
                onChange={(e) => {
                  setFilter({
                    ...filter,
                    filter_by: e.target.value,
                  });
                }}
              >
                <option value="">Please Choose</option>
                <option value="NONE">NONE</option>
                <option value="WARD">WARD</option>
                <option value="HALQA">HALQA</option>
              </Form.Select>
            </Col>

            <Col md="2">
              <Form.Label>ACTION</Form.Label>
              <div>
                <Button
                  variant="danger"
                  onClick={() => {
                    getDataFromServer();
                  }}
                >
                  APPLY FILTER
                </Button>
              </div>
            </Col>
          </Row>
        </Card.Body>
      </Card>
      <Card className="mt-3">
        <Card.Header>EXISTING MEMBER : {members?.length}</Card.Header>
        <Card.Body>
          <div className={styles.tableShell}>
            <Table hover className="text-center align-middle mb-0">
              <thead>
                <tr>
                  <th>
                    SELECT ALL{" "}
                    <input
                      type="checkbox"
                      onChange={() => {
                        if (!allSelected) {
                          let temp = [];

                          members.forEach((item) => {
                            temp.push(item["phone"]);
                          });

                          setSelectedMembers([...temp]);
                          setAllSelected(true);
                        } else {
                          //remove all

                          setSelectedMembers([]);
                        }
                      }}
                    />
                  </th>
                  <th>S.No</th>
                  <th>NAME</th>
                  <th>PARENTAGE</th>
                  <th>DISTRICT</th>
                  <th>CONSTITUENCY</th>
                  <th>HALQA</th>
                  <th>WARD</th>
                  <th>PHONE</th>
                </tr>
              </thead>
              <tbody>{renderTable()}</tbody>
            </Table>
          </div>
        </Card.Body>
        <Card.Footer>
          <Button
            variant="danger"
            size="lg"
            onClick={() => {
              closeModal();
            }}
          >
            CLOSE
          </Button>
          <Button
            variant="success"
            size="lg"
            onClick={() => {
              setRecepients(selectedMembers);
            }}
          >
            PROCEED
          </Button>
        </Card.Footer>
      </Card>
    </>
  );
}
