import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Form, Button } from "react-bootstrap";

import { useFormik } from "formik";

import * as Yup from "yup";

import { BACKEND } from "../../../CONSTANTS";

export default function AddMember() {
  let [preview, setPreview] = React.useState(null);

  let [LocationData, setLocationData] = React.useState(null);

  async function getLocationData() {
    try {
      let res = await fetch(BACKEND + "/location");
      if (res.ok) {
        let DATA = await res.json();
        console.log(DATA);
        setLocationData(DATA);
      } else {
        alert("ERROR: ", await res.text());
      }
    } catch (error) {
      alert("CLIENT ERROR: ", error.message);
    }
  }

  function renderHalqaFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }

    if (LocationData?.HALQAS[constituency])
      return LocationData?.HALQAS[constituency];
    else return [];
  }

  function renderConstituencyFromDistrict(district) {
    if (!district) {
      return [];
    }
    if (LocationData?.CONSTITUENCIES[district]) {
      return LocationData?.CONSTITUENCIES[district];
    } else return [];
  }

  function renderWardsFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }
    if (LocationData?.WARDS[constituency]) {
      return LocationData?.WARDS[constituency];
    } else return [];
  }

  function renderBoothsFromHalqas(halqa) {
    if (!halqa) {
      return [];
    }

    if (LocationData?.BOOTHS[halqa]) {
      return LocationData?.BOOTHS[halqa];
    } else return [];
  }

  React.useEffect(() => {
    getLocationData();
  }, []);

  let initialValues = {
    name: "",
    parentage: "",
    phone: "",
    whatsapp: "",
    email: "",
    district: "",
    constituency: "",
    ward: "",
    halqa: "NA",
    mohalla: "",
    dob: "",
    password: "",
    photo: null,
  };

  let validationSchema = Yup.object({
    name: Yup.string().required(),
    parentage: Yup.string().required(),
    phone: Yup.string().length(10).required(),
    whatsapp: Yup.string().length(10),
    email: Yup.string().email(),
    district: Yup.string().required(),
    constituency: Yup.string().required(),
    ward: Yup.string().required(),
    halqa: Yup.string().required(),
    mohalla: Yup.string().required(),
    dob: Yup.date().required(),
    photo: Yup.mixed().required("Please upload your photograph"),
    password: Yup.string().required().min(6),
  });

  let formik = useFormik({
    initialValues,
    validationSchema,
    onSubmit: handleServerUpload,
  });

  // console.log(formik.values);

  const convertToBase64 = (file) => {
    return new Promise((resolve, reject) => {
      const fileReader = new FileReader();
      fileReader.readAsDataURL(file);
      fileReader.onload = () => {
        resolve(fileReader.result);
      };
      fileReader.onerror = (error) => {
        reject(error);
      };
    });
  };

  async function handleServerUpload(values) {
    try {
      console.log(values);

      let file = values["photo"]["name"];

      //file:///data/user/0/host.exp.exponent/cache/ExperienceData/%2540anonymous%252Fmobile-83b2ae8d-080a-4c6e-8950-c08074b9d820/Camera/ce4392f8-4846-40fc-b36b-c9858c3da762.jpg
      let extension = file.split(".");
      extension = extension[extension.length - 1];
      let filename = file;

      filename = filename.replace(" ", "-");
      filename = filename.replace("%", "_");

      let IMG = {
        name: "photo",
        filename: `${filename}`,
        type: `image/${extension}`,
      };

      let tempIMG = await convertToBase64(values["photo"]);

      let base64Image = tempIMG.split(";base64,").pop();

      IMG["base64"] = base64Image;

      let DATA = { ...values, IMG };

      console.log({
        DATA,
      });

      let res = await fetch(BACKEND + "/member/register", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
        }),
        body: JSON.stringify(DATA),
      });

      if (res.ok) {
        alert("MEMBER ADDED SUCCESS");
        setPreview(null);
        formik.resetForm();
      } else {
        alert("ERROR: " + (await res.text()));
      }
    } catch (error) {
      alert("CLIENT ERROR: " + error.message);
    }
  }

  function handleFileUpload(
    key,
    event,
    type = ["image/png", "image/jpeg", "image/jpg"]
  ) {
    console.log({ event });

    let file = event.target.files[0];

    if (!file) {
      console.log("CANCEL CLICKED");
      event.target.value = null;
      setPreview(null);
      formik.setFieldValue(key, "");
      return;
    }
    //CHECK FOR FILE TYPE

    let file_type_matches = false;

    for (let filetype of type) {
      console.log(filetype);
      if (file["type"] === filetype) {
        file_type_matches = true;
        break;
      }
    }

    if (!file_type_matches) {
      alert("Please upload specified format file");
      event.target.value = null;
      return;
    }

    let preview_url = URL.createObjectURL(file);

    formik.setFieldValue(key, file);

    setPreview(preview_url);
  }

  if (LocationData === null) {
    return (
      <Template>
        <div className={styles.page}>
          <section className={styles.hero}>
            <div className={styles.eyebrow}>Member management</div>
            <h1 className={styles.title}>Add a new member</h1>
            <p className={styles.subtext}>Preparing location data and form fields…</p>
          </section>
          <Card className={styles.panel}>
            <Card.Body className={styles.panelBody}>Loading, please wait ...</Card.Body>
          </Card>
        </div>
      </Template>
    );
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Member management</div>
              <h1 className={styles.title}>Add a new member</h1>
              <p className={styles.subtext}>
                Create a complete member profile with location, identity, and photo details.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>Responsive form</span>
              <span className={styles.metaPill}>Photo upload</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>New member details</Card.Header>
          <Card.Body className={styles.panelBody}>
          <Row className="g-3">
            <Form.Group md="5" as={Col} className="my-3">
              <Form.Label>Full Name</Form.Label>
              <Form.Control name="name" {...formik.getFieldProps("name")} />
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label>Parentage</Form.Label>
              <Form.Control
                name="parentage"
                {...formik.getFieldProps("parentage")}
              />
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>Date of Birth</Form.Label>
              <Form.Control
                type="date"
                name="dob"
                {...formik.getFieldProps("dob")}
              />
            </Form.Group>
          </Row>

          <Row className="g-3">
            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>Phone</Form.Label>
              <Form.Control name="phone" {...formik.getFieldProps("phone")} />
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>WhatsApp</Form.Label>
              <Form.Control
                name="whatsapp"
                {...formik.getFieldProps("whatsapp")}
              />
            </Form.Group>

            <Form.Group md="6" as={Col} className="my-3">
              <Form.Label>Email (Optional)</Form.Label>
              <Form.Control name="email" {...formik.getFieldProps("email")} />
            </Form.Group>
          </Row>

          <Row className="g-3">
            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label>District</Form.Label>
              <Form.Select
                name="district"
                {...formik.getFieldProps("district")}
              >
                <option value="">Please Choose</option>
                {LocationData?.DISTRICTS.map((district, index) => {
                  return <option key={district}>{district}</option>;
                })}
              </Form.Select>
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label>Constituency</Form.Label>
              <Form.Select
                name="constituency"
                {...formik.getFieldProps("constituency")}
              >
                <option value="">Please Choose</option>
                {renderConstituencyFromDistrict(formik.values["district"]).map(
                  (constituency, index) => {
                    return (
                      <option key={constituency} value={constituency}>
                        {constituency}
                      </option>
                    );
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="4" as={Col} className="my-3">
              <Form.Label>Halqa</Form.Label>
              <Form.Select name="halqa" {...formik.getFieldProps("halqa")}>
                <option value="">Please Choose</option>
                {renderHalqaFromConstituency(formik.values["constituency"]).map(
                  (halqa, index) => {
                    return <option key={halqa}>{halqa}</option>;
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>Ward</Form.Label>
              <Form.Select name="ward" {...formik.getFieldProps("ward")}>
                <option value="">Please Choose</option>
                {renderWardsFromConstituency(formik.values["constituency"]).map(
                  (ward, index) => {
                    return <option key={ward}>{ward}</option>;
                  }
                )}
              </Form.Select>
            </Form.Group>

            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>Mohalla</Form.Label>
              <Form.Control
                name="mohalla"
                {...formik.getFieldProps("mohalla")}
              />
            </Form.Group>
          </Row>

          <Row className="g-3">
            <Form.Group md="3" as={Col} className="my-3">
              <Form.Label>Member Photo</Form.Label>
              <Form.Control
                type="file"
                name="photo"
                accept="image/*"
                onChange={(e) => {
                  handleFileUpload("photo", e);
                }}
              />
            </Form.Group>

            {preview === null ? null : (
              <Form.Group md="5" as={Col} className="my-3">
                <img src={preview} width="100%" height="auto" />
              </Form.Group>
            )}
          </Row>

          <Row className="g-3">
            <Form.Group md="6" as={Col} className="my-3">
              <Form.Label>Choose a Passowrd (min 6 characters)</Form.Label>
              <Form.Control
                name="password"
                {...formik.getFieldProps("password")}
              />
            </Form.Group>
          </Row>

          <Row className="g-3">
            <div className="my-3 d-flex justify-content-end">
              <Button
                disabled={!formik.dirty || !formik.isValid}
                variant={"dark"}
                onClick={formik.handleSubmit}
              >
                Upload Member Details
              </Button>
            </div>
          </Row>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
