import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Alert, Form, Button, Table } from "react-bootstrap";
import { BACKEND } from "../../../CONSTANTS";
import AuthContext from "../../../context/auth";

export default function FeedbackReceived() {
  const authContext = React.useContext(AuthContext);

  let [feedback, setFeedback] = React.useState([]);

  async function getDataFromServer() {
    try {
      let res = await fetch(BACKEND + "/dashboard/feedback/view", {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["token"],
        }),
      });

      if (res.ok) {
        setFeedback(await res.json());
      }
    } catch (error) {}
  }

  React.useEffect(() => {
    getDataFromServer();
  }, []);

  function renderFeedback() {
    if (feedback.length === 0) {
      return <span>Please Wait Loading ...</span>;
    } else {
      let temp = feedback.map((item, index) => {
        return <Feedback detail={item} />;
      });

      return temp;
    }
  }

  return (
    <Template>
      <Card className={styles.panel}>
        <Card.Header className={styles.panelHeader}>FEEDBACK RECEIVED</Card.Header>
        <Card.Body className={styles.panelBody}>
          <div>{renderFeedback()}</div>
        </Card.Body>
      </Card>
    </Template>
  );
}

function Feedback({ detail }) {
  return (
    <Card className="my-4">
      <Card.Header>
        {" "}
        {new Date(detail["received_at"]).toDateString()} : {detail["subject"]}
      </Card.Header>
      <Card.Body className={styles.panelBody}>
        <div>
          <p>{detail["message"]}</p>
        </div>
        <hr />
        <div className={styles.tableShell}>
          <Table className="mb-0 align-middle">
            <tbody>
              <tr>
                <td>Name</td>
                <td>{detail["name"]}</td>
              </tr>

              <tr>
                <td>Parentage</td>
                <td>{detail["parentage"]}</td>
              </tr>

              <tr>
                <td>Phone</td>
                <td>{detail["phone"]}</td>
              </tr>

              <tr>
                <td>District</td>
                <td>{detail["district"]}</td>
              </tr>

              <tr>
                <td>Constituency</td>
                <td>{detail["constituency"]}</td>
              </tr>

              <tr>
                <td>Ward</td>
                <td>{detail["ward"]}</td>
              </tr>

              <tr>
                <td>Member id</td>
                <td>{detail["member_id"]}</td>
              </tr>
            </tbody>
          </Table>
        </div>
        <div></div>
      </Card.Body>
    </Card>
  );
}
