import React, { useEffect, useRef } from "react";

import { Modal } from "react-bootstrap";

import Template from "../../../Components/PageTemplate/Template";

import {
  Button,
  Container,
  Spinner,
  Row,
  Col,
  Alert,
  Form,
} from "react-bootstrap";

import { socket } from "../../../utils/socket";

import QRCode from "react-qr-code";

import RecepientSelector from "./SelectRecepient/Birthday";

export default function BirthdayWishes() {
  const [status, setStatus] = React.useState("DISCONNECTED");
  const [qrData, setQRData] = React.useState(null);

  const getWhatsAppQRCode = () => {
    socket.emit("generateQR");
    setStatus("REQUESTED");
  };

  useEffect(() => {
    socket.on("QRGenerated", (qr) => {
      console.log(qr);
      if (status !== "CONNECTED") {
        setStatus("GENERATED");
        setQRData(qr);
      }
    });

    socket.on("loadSuccess", () => {
      setStatus("CONNECTED");
    });

    socket.on("meesageResult", (data) => {
      alert("MESSAGE DELIVERED ON WHATSAPP");
      console.log(JSON.parse(data));
    });
  }, []);

  // 3 stages  // DISCONNECTED // //PENDING //CONNECTED

  return (
    <Template>
      <Container style={{ backgroundColor: "white", padding: "2rem" }}>
        <h5>WhatsApp Birthday Wishes!</h5>
        <hr />
        <CurrentStatus
          status={status}
          getWhatsAppQRCode={getWhatsAppQRCode}
          qrData={qrData}
        />
      </Container>
    </Template>
  );
}

function CurrentStatus({ status, getWhatsAppQRCode, qrData }) {
  switch (status) {
    case "DISCONNECTED":
      return (
        <>
          <div>
            CURRENT STATUS:{" "}
            <span style={{ fontWeight: "bold", color: "red" }}>
              {" "}
              DISCONNECTED
            </span>
          </div>
          <div className="mt-3">
            <Button
              onClick={() => {
                getWhatsAppQRCode();
              }}
              variant="success"
            >
              INITIALIZE WHATSAPP WEB CONNECTION
            </Button>
          </div>
        </>
      );

    case "REQUESTED":
      return (
        <>
          <div>
            CURRENT STATUS:{" "}
            <span style={{ fontWeight: "bold", color: "red" }}>
              {" "}
              QR REQUESTED
            </span>
            <Spinner />
          </div>
        </>
      );

    case "GENERATED":
      return (
        <>
          <div>
            CURRENT STATUS:{" "}
            <span style={{ fontWeight: "bold", color: "green" }}>
              {" "}
              QR GENERATED
            </span>
          </div>
          <Row>
            <Col md="3">
              <div className="py-5">
                <QRCode value={qrData} />
              </div>
            </Col>
            <Col>
              <Container>
                <Alert>
                  SCAN THE QR CODE FROM YOUR WHATSAPP APPLICATION TO START
                </Alert>
              </Container>
            </Col>
          </Row>
        </>
      );

    case "CONNECTED":
      return (
        <>
          <div>
            CURRENT STATUS:{" "}
            <span style={{ fontWeight: "bold", color: "green" }}>
              {" "}
              WHATSAPP CONNECTED
            </span>
          </div>
          <hr />
          <div>
            <SendMessage />
          </div>
        </>
      );
  }
}

function SendMessage() {
  const [modalOpen, setmodalOpen] = React.useState(false);
  const [messageData, setMessageData] = React.useState({
    numbers: [],
    message: "",
  });

  function sendMessage() {
    console.log(messageData);
    socket.emit("sendMessage", JSON.stringify(messageData));
  }

  return (
    <div className="py-3">
      <div className="d-flex justify-content-end">
        <Button
          onClick={() => {
            setmodalOpen(true);
          }}
        >
          Choose Recepients
        </Button>
      </div>

      <Modal
        fullscreen={true}
        show={modalOpen}
        onEscapeKeyDown={() => {
          setmodalOpen(false);
        }}
      >
        <Modal.Header>SELECT RECEPIENTS</Modal.Header>
        <Modal.Body>
          <RecepientSelector
            setRecepients={(selectedNums) => {
              setMessageData({
                ...messageData,
                numbers: [...selectedNums],
              });
            }}
            closeModal={() => {
              setmodalOpen(false);
            }}
          />
        </Modal.Body>
      </Modal>
      <Form>
        <Form.Group>
          <Form.Label>RECEPIENTS NUMBERS</Form.Label>
          <Form.Control value={messageData.numbers.join()} />
        </Form.Group>

        <Form.Group className="mt-3">
          <Form.Label>WHATSAPP MESSAGE</Form.Label>
          <Form.Control
            as="textarea"
            value={messageData.message}
            onChange={(e) => {
              setMessageData({
                ...messageData,
                message: e.target.value,
              });
            }}
          />
        </Form.Group>
      </Form>

      <div className="mt-3">
        <Button
          variant="success"
          onClick={() => {
            sendMessage();
          }}
        >
          SEND MESSAGE
        </Button>
      </div>
    </div>
  );
}
