import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Container, Row, Col, Table, Card, Button } from "react-bootstrap";

import BootstrapSwitchButton from "bootstrap-switch-button-react";

import { BACKEND } from "../../../CONSTANTS";

import { useNavigate } from "react-router-dom";
import AuthContext from "../../../context/auth";

export default function SpecialMembers() {
  const authContext = React.useContext(AuthContext);
  let [members, setMembers] = React.useState(null);
  let [toggle, setToggle] = React.useState(false);
  const NAVIGATE = useNavigate();

  async function getDataFromServer() {
    try {
      let res = await fetch(BACKEND + "/dashboard/member/showSpecialMembers", {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["user"]["token"],
        }),
      });

      if (res.ok) {
        setMembers(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  function renderTable() {
    if (members === null) {
      return <span>Loading Data, Please Wait ....</span>;
    }

    let temp = members.map((member, index) => {
      return (
        <tr>
          <td>{index + 1}</td>
          <td>{member["name"]}</td>
          <td>{member["authority"]["designation"]}</td>
          <td>{member["authority"]["district"]}</td>
          <td>{member["authority"]["constituency"]}</td>
          <td>{member["authority"]["zone"]}</td>
          <td>{member["authority"]["block"]}</td>
          <td>{member["authority"]["halqa"]}</td>
          <td>{member["authority"]["ward"]}</td>
          <td>{member["authority"]["mohalla"]}</td>

          <td>
            <Button
              variant="success"
              onClick={(e) => {
                NAVIGATE(
                  "/dashboard/members/profile?id=" + member["member_id"]
                );
              }}
            >
              VIEW DETAILS
            </Button>
          </td>
        </tr>
      );
    });

    return temp;
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Member hierarchy</div>
              <h1 className={styles.title}>Special Members</h1>
              <p className={styles.subtext}>
                Review elevated member records in a cleaner table with mobile-friendly spacing.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>{members?.length || 0} members</span>
              <span className={styles.metaPill}>Authority mapping</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Special member directory</Card.Header>
          <Card.Body className={styles.panelBody}>
            <div className={styles.tableShell}>
              <Table hover className="text-center align-middle mb-0">
                <thead>
                  <tr>
                    <th>S.No</th>
                    <th>Name</th>
                    <th>Designation</th>
                    <th>District</th>
                    <th>Constituency</th>
                    <th>Zone</th>
                    <th>Block</th>
                    <th>Halqa</th>
                    <th>Ward</th>
                    <th>Mohalla</th>
                    <th>Member Profile</th>
                  </tr>
                </thead>
                <tbody>{renderTable()}</tbody>
              </Table>
            </div>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
