import React from "react";
import Template from "../../../Components/PageTemplate/Template";

import { Card, Alert, Form, Row, Col, Button } from "react-bootstrap";

import * as Yup from "yup";

import { useFormik } from "formik";
import { BACKEND } from "../../../CONSTANTS";
import AuthContext from "../../../context/auth";

export default function AddUser() {
  const authContext = React.useContext(AuthContext);

  let [otp, setOtp] = React.useState({
    verified: false,
    value: "",
    state: "INITIAL",
  });

  let [LocationData, setLocationData] = React.useState(null);

  async function getLocationData() {
    try {
      let res = await fetch(BACKEND + "/location");
      if (res.ok) {
        let DATA = await res.json();
        console.log(DATA);
        setLocationData(DATA);
      } else {
        alert("ERROR: ", await res.text());
      }
    } catch (error) {
      alert("CLIENT ERROR: ", error.message);
    }
  }

  function renderHalqaFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }

    if (LocationData?.HALQAS[constituency])
      return LocationData?.HALQAS[constituency];
    else return [];
  }

  function renderConstituencyFromDistrict(district) {
    if (!district) {
      return [];
    }
    if (LocationData?.CONSTITUENCIES[district]) {
      return LocationData?.CONSTITUENCIES[district];
    } else return [];
  }

  function renderWardsFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }
    if (LocationData?.WARDS[constituency]) {
      return LocationData?.WARDS[constituency];
    } else return [];
  }

  function renderBoothsFromHalqas(halqa) {
    if (!halqa) {
      return [];
    }

    if (LocationData?.BOOTHS[halqa]) {
      return LocationData?.BOOTHS[halqa];
    } else return [];
  }

  React.useEffect(() => {
    getLocationData();
  }, []);

  let initialValues = {
    name: "",
    email: "",
    phone: "",
    assigned_role: "",
    district: "",
    constituency: "",
    ward: "",
    halqa: "",

    password: "",
    confirm_password: "",
  };

  let validationSchema = Yup.object({
    name: Yup.string().required(),
    email: Yup.string().email().required(),
    phone: Yup.string().required(),
    assigned_role: Yup.string().required(),
    district: Yup.string().required(),
    constituency: Yup.string().required(),
    ward: Yup.string().required(),
    halqa: Yup.string().required(),

    password: Yup.string().required(),
    confirm_password: Yup.string()
      .oneOf([Yup.ref("password"), null], "Password Must Match")
      .required(),
  });

  const formik = useFormik({
    initialValues,
    validationSchema,
  });

  console.log({
    values: formik.values,
  });

  async function sendOtp() {
    try {
      let phone = formik.values.phone;
      if (!phone && phone?.length !== 10) {
        return;
      }

      //SEND OTP

      let res = await fetch(BACKEND + "/OTP/generate/" + phone + "/user", {
        method: "POST",
      });

      if (res.ok) {
        alert("SMS DELIVERED OTP");
        let otpState = { ...otp };
        otpState["state"] = "SENT";
        setOtp(otpState);
      } else {
        alert("ERROR" + (await res.text()));
      }
    } catch (error) {
      alert("ERROR CLIENT: " + error.message);
    }
  }

  async function VerifyOtp() {
    try {
      let OTP = otp["value"];
      if (!OTP) {
        return;
      }

      //SEND OTP

      let res = await fetch(
        BACKEND + "/OTP/verify/" + formik.values["phone"] + "/" + OTP,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["token"],
          }),
        }
      );

      if (res.ok) {
        alert("OTP VERIFIED");
        let otpState = { ...otp };
        otpState["state"] = "VERIFIED";
        otpState["verified"] = true;
        setOtp(otpState);
      } else {
        alert("ERROR" + (await res.text()));
      }
    } catch (error) {
      alert("ERROR CLIENT: " + error.message);
    }
  }

  async function sendDetailsToServer() {
    try {
      let DATA = formik.values;

      delete DATA["confirm_password"];

      let res = await fetch(`${BACKEND}/dashboard/user/new`, {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
          "x-auth-token": authContext["token"],
        }),
        body: JSON.stringify(DATA),
      });

      if (res.ok) {
        alert("USER ADDED SUCCESSFULLY");
        formik.resetForm();
        setOtp({ verified: false, value: "", stage: "INITIAL" });
      } else alert("ERROR " + (await res.text()));
    } catch (error) {
      alert("CLIENT ERROR: ", error.message);
    }
  }

  if (LocationData === null) {
    return (
      <Template>
        <div>LOADING, PLEASE WAIT</div>
      </Template>
    );
  }

  return (
    <Template>
      <Card>
        <Card.Header>ADD A NEW USER</Card.Header>
        <Card.Body>
          <Form>
            <Row>
              <Form.Group as={Col} md="4" className="my-3">
                <Form.Label>Name</Form.Label>
                <Form.Control name="name" {...formik.getFieldProps("name")} />
              </Form.Group>

              <Form.Group as={Col} md="6" className="my-3">
                <Form.Label>Email Address</Form.Label>
                <Form.Control name="email" {...formik.getFieldProps("email")} />
              </Form.Group>
            </Row>
            <hr />

            <Row>
              <Form.Group as={Col} md="4" className="my-3">
                <Form.Label>Role to Assign</Form.Label>
                <Form.Select
                  name="assigned_role"
                  {...formik.getFieldProps("assigned_role")}
                >
                  <option>Please Choose</option>
                  <option value="SUPER USER">Super User</option>
                  <option value="CONSTITUENCY">Constituency User</option>
                  <option value="HALQA">HALQA User</option>
                  <option value="WARD">Ward User</option>
                </Form.Select>
              </Form.Group>

              <Form.Group md="4" as={Col} className="my-3">
                <Form.Label>District</Form.Label>
                <Form.Select
                  name="district"
                  {...formik.getFieldProps("district")}
                >
                  <option value="">Please Choose</option>
                  {LocationData?.DISTRICTS.map((district, index) => {
                    return <option key={district}>{district}</option>;
                  })}
                </Form.Select>
              </Form.Group>

              <Form.Group md="4" as={Col} className="my-3">
                <Form.Label>Constituency</Form.Label>
                <Form.Select
                  name="constituency"
                  {...formik.getFieldProps("constituency")}
                >
                  <option value="">Please Choose</option>
                  {renderConstituencyFromDistrict(
                    formik.values["district"]
                  ).map((constituency, index) => {
                    return (
                      <option key={constituency} value={constituency}>
                        {constituency}
                      </option>
                    );
                  })}
                </Form.Select>
              </Form.Group>

              <Form.Group md="4" as={Col} className="my-3">
                <Form.Label>Halqa</Form.Label>
                <Form.Select name="halqa" {...formik.getFieldProps("halqa")}>
                  <option value="">Please Choose</option>
                  {renderHalqaFromConstituency(
                    formik.values["constituency"]
                  ).map((halqa, index) => {
                    return <option key={halqa}>{halqa}</option>;
                  })}
                </Form.Select>
              </Form.Group>

              <Form.Group md="3" as={Col} className="my-3">
                <Form.Label>Ward</Form.Label>
                <Form.Select name="ward" {...formik.getFieldProps("ward")}>
                  <option value="">Please Choose</option>
                  {renderWardsFromConstituency(
                    formik.values["constituency"]
                  ).map((ward, index) => {
                    return <option key={ward}>{ward}</option>;
                  })}
                </Form.Select>
              </Form.Group>
            </Row>

            <Row>
              <Form.Group as={Col} md="3" className="my-3">
                <Form.Label>Phone Number</Form.Label>
                <Form.Control
                  disabled={otp["state"] !== "INITIAL"}
                  type="number"
                  name="phone"
                  {...formik.getFieldProps("phone")}
                />
              </Form.Group>

              <Form.Group as={Col} md="2" className="my-3">
                <Form.Label>SEND</Form.Label>
                <div>
                  <Button
                    disabled={otp["state"] !== "INITIAL"}
                    variant="danger"
                    onClick={() => {
                      sendOtp();
                    }}
                  >
                    SEND OTP
                  </Button>
                </div>
              </Form.Group>

              <Form.Group as={Col} md="3" className="my-3">
                <Form.Label>OTP RECEIVED</Form.Label>
                <Form.Control
                  value={otp["value"]}
                  disabled={otp["verified"] === true}
                  onChange={(e) => {
                    let val = e.target.value;
                    setOtp({ ...otp, value: val });
                  }}
                />
              </Form.Group>

              <Form.Group as={Col} md="2" className="my-3">
                <Form.Label>VERIFY</Form.Label>
                <div>
                  <Button
                    variant="danger"
                    disabled={otp["verified"]}
                    onClick={() => {
                      if (otp["verified"]) {
                        return;
                      }

                      VerifyOtp();
                    }}
                  >
                    VERIFY OTP
                  </Button>
                </div>
              </Form.Group>
            </Row>
            <hr />
            <Row>
              <Form.Group as={Col} md="3" className="my-3">
                <Form.Label>Password</Form.Label>
                <Form.Control
                  name="password"
                  {...formik.getFieldProps("password")}
                />
              </Form.Group>

              <Form.Group as={Col} md="3" className="my-3">
                <Form.Label>Confirm Password</Form.Label>
                <Form.Control
                  name="confirm_password"
                  {...formik.getFieldProps("confirm_password")}
                />
              </Form.Group>
            </Row>
            <hr />
            <div className="py-3">
              <Button
                variant="success"
                size="lg"
                disabled={!formik.isValid || !otp["verified"]}
                onClick={() => {
                  sendDetailsToServer();
                }}
              >
                REGISTER NEW USER
              </Button>
            </div>
          </Form>
        </Card.Body>
      </Card>
    </Template>
  );
}
