import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import screenStyles from "../../../Components/PageTemplate/DashboardScreen.module.css";
import styles from "./MemberProfile.module.css";

import {
  Row,
  Col,
  Card,
  Button,
  Form,
} from "react-bootstrap";

import { BACKEND } from "../../../CONSTANTS";

import { useNavigate } from "react-router-dom";

import { useLocation } from "react-router-dom";
import AuthContext from "../../../context/auth";

import { useFormik } from "formik";

import * as Yup from "yup";

export default function MemberProfile() {
  const Navigator = useNavigate();
  let initialValues = {
    designation: "",
    district: "",
    constituency: "",
    zone: "",
    block: "",
    halqa: "",
    ward: "",
    booth: "",
    mohalla: "",
  };

  let [LocationData, setLocationData] = React.useState(null);

  async function getLocationData() {
    try {
      let res = await fetch(BACKEND + "/location");
      if (res.ok) {
        let DATA = await res.json();
        console.log(DATA);
        setLocationData(DATA);
      } else {
        alert("ERROR: ", await res.text());
      }
    } catch (error) {
      alert("CLIENT ERROR: ", error.message);
    }
  }

  React.useEffect(() => {
    getLocationData();
  }, []);

  let validationSchema = Yup.object({
    designation: Yup.string().required(),
    district: Yup.string().required(),
    constituency: Yup.string().required(),
    zone: Yup.string().required(),
    block: Yup.string().required(),
    halqa: Yup.string().required(),
    ward: Yup.string().required(),
    booth: Yup.string().required(),
    mohalla: Yup.string().required(),
  });

  const formik = useFormik({
    initialValues,
    validationSchema,
    onSubmit: elevateMember,
  });

  const authContext = React.useContext(AuthContext);
  let [member, setMember] = React.useState(null);
  let [toggle, setToggle] = React.useState(false);
  let [showElevationForm, setShowElevationForm] = React.useState(false);

  const search = useLocation().search;
  const member_id = new URLSearchParams(search).get("id");

  function renderHalqaFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }

    if (LocationData?.HALQAS[constituency])
      return LocationData?.HALQAS[constituency];
    else return [];
  }

  function renderConstituencyFromDistrict(district) {
    if (!district) {
      return [];
    }
    if (LocationData?.CONSTITUENCIES[district]) {
      return LocationData?.CONSTITUENCIES[district];
    } else return [];
  }

  function renderWardsFromConstituency(constituency) {
    if (!constituency) {
      return [];
    }
    if (LocationData?.WARDS[constituency]) {
      return LocationData?.WARDS[constituency];
    } else return [];
  }

  function renderBoothsFromHalqas(halqa) {
    if (!halqa) {
      return [];
    }

    if (LocationData?.BOOTHS[halqa]) {
      return LocationData?.BOOTHS[halqa];
    } else return [];
  }

  // async function toggleUserActivation(phone) {
  //   try {
  //     let res = await fetch(
  //       BACKEND + "/dashboard/member/toggleActivation/" + phone,
  //       {
  //         method: "POST",
  //         headers: new Headers({
  //           "x-auth-token": authContext["user"]["token"],
  //         }),
  //       }
  //     );

  //     if (res.ok) {
  //       alert("Activation State CHANGED");
  //       setToggle(!toggle);
  //     }
  //   } catch (error) {
  //     alert("ERROR " + error.message);
  //   }
  // }

  async function revokeMemberElevation() {
    try {
      let res = await fetch(
        BACKEND + "/dashboard/member/revokeElevation/" + member_id,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["token"],
          }),
        }
      );

      if (res.ok) {
        //SUCCESS
        alert("SUCCESS: ", await res.text());
        setToggle(!toggle);
      } else {
        //HANDLE ERROR
        alert("ERROR: ", await res.text());
      }
    } catch (error) {
      alert("CLIENT ERROR:", error.message);
    }
  }

  async function elevateMember(values) {
    try {
      let DATA = {
        member_id: member["member_id"],
        ...values,
      };
      let res = await fetch(BACKEND + "/dashboard/member/elevation", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
          "x-auth-token": authContext["token"],
        }),
        body: JSON.stringify(DATA),
      });

      if (res.ok) {
        //SUCCESS
        alert("SUCCESS: " + (await res.text()));
        formik.resetForm();
        setToggle(!toggle);
      } else {
        //HANDLE ERROR
        alert("ERROR: " + (await res.text()));
      }
    } catch (error) {
      alert("CLIENT ERROR:" + error.message);
    }
  }

  async function getDataFromServer() {
    try {
      let res = await fetch(
        BACKEND + "/dashboard/member/profile/" + member_id,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["user"]["token"],
          }),
        }
      );

      if (res.ok) {
        setMember(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  function renderAttributes() {
    if (!member) {
      return null;
    }

    let keys = Object.keys(member);

    let temp = [];

    let invalid_keys = [
      "password",
      "img",
      "IMG",
      "expoPushToken",
      "_id",
      "authority",
    ];

    temp = keys.map((key) => {
      if (invalid_keys.includes(key)) {
        return null;
      } else if (key === "registered_on" || key === "expiration") {
        return (
          <div key={key} className={styles.attributeItem}>
            <span className={styles.attributeKey}>{key.replaceAll("_", " ")}</span>
            <span className={styles.attributeValue}>{new Date(member[key]).toDateString()}</span>
          </div>
        );
      } else
        return (
          <div key={key} className={styles.attributeItem}>
            <span className={styles.attributeKey}>{key.replaceAll("_", " ")}</span>
            <span className={styles.attributeValue}>{String(member[key])}</span>
          </div>
        );
    });

    return temp;
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  console.log(formik.values);

  return (
    <Template>
      <div className={screenStyles.page}>
        <section className={`${screenStyles.hero} ${styles.heroAccent}`}>
          <div className={screenStyles.heroTop}>
            <div>
              <div className={screenStyles.eyebrow}>Member profile</div>
              <h1 className={screenStyles.title}>{member?.name || "Member Details"}</h1>
              <p className={screenStyles.subtext}>
                Review the member profile, update details, and manage designation elevation in one place.
              </p>
            </div>
            <div className={screenStyles.heroMeta}>
              <span className={screenStyles.metaPill}>ID: {member_id}</span>
              <span className={screenStyles.metaPill}>{member?.designation || "No designation"}</span>
            </div>
          </div>
        </section>

        <Card className={`${screenStyles.panel} ${styles.overviewCard}`}>
          <Card.Header className={screenStyles.panelHeader}>Member overview</Card.Header>
          <Card.Body className={screenStyles.panelBody}>
            <Row className="g-4">
              <Col lg="4">
                <div className={styles.profileRail}>
                  <div className={styles.imageFrame}>
                    <img
                      src={`${BACKEND}/dashboard/member/image/${member_id}?token=${authContext["token"]}`}
                      alt="member_image"
                      style={{
                        width: "100%",
                        borderRadius: "12px",
                        display: "block",
                      }}
                    />
                  </div>

                  <div className="d-grid gap-2">
                    <Button
                      variant="dark"
                      onClick={() => {
                        Navigator("/dashboard/members/edit?id=" + member_id);
                      }}
                    >
                      Edit Member
                    </Button>
                  </div>

                  <div className={styles.pillRow}>
                    <span className={styles.miniPill}>Phone: {member?.phone || "N/A"}</span>
                    <span className={styles.miniPill}>Ward: {member?.ward || "N/A"}</span>
                  </div>

                  <div className={screenStyles.kvItem}>
                    <span className={screenStyles.kvLabel}>Current designation</span>
                    <span className={screenStyles.kvValue}>{member?.designation || "N/A"}</span>
                  </div>
                </div>
              </Col>

              <Col lg="8">
                <div className={styles.tableTitle}>Profile attributes</div>
                <div className={`${screenStyles.tableShell} ${styles.profileTableWrap}`}>
                  <div className={styles.attributeGrid}>{renderAttributes()}</div>
                </div>
              </Col>
            </Row>
          </Card.Body>
        </Card>

        {LocationData === null ? null : (
          <Card className={`${screenStyles.panel} ${styles.elevationCard}`}>
            <Card.Header className={screenStyles.panelHeader}>Elevate Member Designation</Card.Header>
            <Card.Body className={screenStyles.panelBody}>
              <div className={styles.sectionHint}>
                Select a role and assignment details to elevate this member in the organizational hierarchy.
              </div>

              <Button
                variant="outline-secondary"
                size="sm"
                className={styles.mobileElevateToggle}
                onClick={() => setShowElevationForm(!showElevationForm)}
              >
                {showElevationForm ? "Hide Elevation Form" : "Show Elevation Form"}
              </Button>

              <div className={`${styles.mobileFormWrap} ${showElevationForm ? styles.mobileFormOpen : ""}`}>
              <Form>
                <Row className={`g-3 ${styles.fieldGrid}`}>
                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>DESIGNATION</Form.Label>
                  <Form.Select
                    name="designation"
                    {...formik.getFieldProps("designation")}
                  >
                    <option value="">Please Choose</option>

                  
                    <optgroup label="PRESIDENT">
                      <option>CONSTITUENCY - PRESIDENT</option>
                      <option>BLOCK - PRESIDENT</option>
                      <option>ZONE - PRESIDENT</option>
                      <option>HALQA - PRESIDENT</option>
                      <option>WARD - PRESIDENT</option>
                      <option>BOOTH - PRESIDENT</option>
                      <option>MOHALLA - PRESIDENT</option>
                    </optgroup>

                    <optgroup label="VICE PRESIDENT">
                      <option>BLOCK - VICE PRESIDENT</option>
                      <option>ZONE - VICE PRESIDENT</option>
                      <option>CONSTITUENCY - VICE PRESIDENT</option>
                      <option>HALQA - VICE PRESIDENT</option>
                      <option>WARD - VICE PRESIDENT</option>
                      <option>BOOTH - VICE PRESIDENT</option>
                      <option>MOHALLA - VICE PRESIDENT</option>
                    </optgroup>

                    <optgroup label="SECRETARY">
                      <option>BLOCK - SECRETARY</option>
                      <option>ZONE - SECRETARY</option>
                      <option>CONSTITUENCY - SECRETARY</option>
                      <option>HALQA - SECRETARY</option>
                      <option>WARD - SECRETARY</option>
                      <option>BOOTH - SECRETARY</option>
                      <option>MOHALLA - SECRETARY</option>
                    </optgroup>

                    <optgroup label="ORGANIZER">
                      <option>BLOCK - ORGANIZER</option>
                      <option>ZONE - ORGANIZER</option>
                      <option>CONSTITUENCY - ORGANIZER</option>
                      <option>HALQA - ORGANIZER</option>
                      <option>WARD - ORGANIZER</option>
                      <option>BOOTH - ORGANIZER</option>
                      <option>MOHALLA - ORGANIZER</option>
                    </optgroup>

                    <optgroup label="DELEGATE">
                      <option>BLOCK - DELEGATE</option>
                      <option>ZONE - DELEGATE</option>
                      <option>CONSTITUENCY - DELEGATE</option>
                      <option>HALQA - DELEGATE</option>
                      <option>WARD - DELEGATE</option>
                      <option>BOOTH - DELEGATE</option>
                      <option>MOHALLA - DELEGATE</option>
                    </optgroup>

                    <optgroup label="EXECUTIVE COMMITTEE">
                      <option>EXECUTICE COMMITTEE MEMBER</option>
                    </optgroup>

                    <optgroup label="YOUTH WING">
                      <option>YOUTH PRESIDENT</option>
                      <option>YOUTH VICE PRESIDENT</option>
                      <option>YOUTH SECRETARY</option>
                      <option>YOUTH JOINT SECRETARY</option>
                      <option>YOUTH ORGANIZER</option>
                    </optgroup>

                    <optgroup label="WOMEN'S WING">
                      <option>WOMEN'S WING PRESIDENT</option>
                      <option>WOMEN'S WING VICE PRESIDENT</option>
                      <option>WOMEN'S WING SECRETARY</option>
                      <option>WOMEN'S WING JOINT SECRETARY</option>
                      <option>WOMEN'S WING ORGANIZER</option>
                    </optgroup>
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="2" className={styles.field}>
                  <Form.Label>DISTRICT</Form.Label>
                  <Form.Select
                    name="district"
                    {...formik.getFieldProps("district")}
                  >
                    <option value="">Please Choose</option>
                    {LocationData?.DISTRICTS.map((district, index) => {
                      return <option key={district}>{district}</option>;
                    })}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>CONSTITUENCY</Form.Label>
                  <Form.Select
                    name="constituency"
                    {...formik.getFieldProps("constituency")}
                  >
                    <option value="">Please Choose</option>
                    {renderConstituencyFromDistrict(
                      formik.values["district"]
                    ).map((constituency, index) => {
                      return (
                        <option key={constituency} value={constituency}>
                          {constituency}
                        </option>
                      );
                    })}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="2" className={styles.field}>
                  <Form.Label>ZONE</Form.Label>
                  <Form.Select name="zone" {...formik.getFieldProps("zone")}>
                    <option value="">Please Choose</option>
                    {LocationData?.ZONES.map((zone, index) => {
                      return <option key={zone}>{zone}</option>;
                    })}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="2" className={styles.field}>
                  <Form.Label>BLOCK</Form.Label>
                  <Form.Select name="block" {...formik.getFieldProps("block")}>
                    <option value="">Please Choose</option>
                    {LocationData.BLOCKS.map((block, index) => {
                      return <option key={block}>{block}</option>;
                    })}
                  </Form.Select>
                </Form.Group>
              </Row>

              <Row className={`g-3 ${styles.fieldGrid}`}>
                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>HALQA</Form.Label>
                  <Form.Select name="halqa" {...formik.getFieldProps("halqa")}>
                    <option value="">Please Choose</option>
                    {renderHalqaFromConstituency(
                      formik.values["constituency"]
                    ).map((halqa, index) => {
                      return <option key={halqa}>{halqa}</option>;
                    })}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>WARD</Form.Label>
                  <Form.Select name="ward" {...formik.getFieldProps("ward")}>
                    <option value="">Please Choose</option>
                    {renderWardsFromConstituency(
                      formik.values["constituency"]
                    ).map((ward, index) => {
                      return <option key={ward}>{ward}</option>;
                    })}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>BOOTH</Form.Label>
                  <Form.Select name="booth" {...formik.getFieldProps("booth")}>
                    <option value="">Please Choose</option>
                    {renderBoothsFromHalqas(formik.values["halqa"]).map(
                      (halqa, index) => {
                        return <option key={halqa}>{halqa}</option>;
                      }
                    )}
                  </Form.Select>
                </Form.Group>

                <Form.Group as={Col} md="3" className={styles.field}>
                  <Form.Label>MOHALLA</Form.Label>
                  <Form.Control
                    name="mohalla"
                    {...formik.getFieldProps("mohalla")}
                  />
                </Form.Group>
              </Row>

              <Row>
                <div className={styles.actions}>
                  <Button
                    variant="outline-secondary"
                    onClick={async () => {
                      await revokeMemberElevation();
                    }}
                  >
                    Revoke Elevation
                  </Button>
                  <Button
                    disabled={!formik.dirty || !formik.isValid}
                    variant="dark"
                    onClick={formik.handleSubmit}
                  >
                    Elevate Member Designation
                  </Button>
                </div>
              </Row>
            </Form>
            </div>
            </Card.Body>
          </Card>
        )}
      </div>
    </Template>
  );
}
