import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Container, Row, Col, Table, Card, Button } from "react-bootstrap";

import BootstrapSwitchButton from "bootstrap-switch-button-react";

import { BACKEND } from "../../../CONSTANTS";

import AuthContext from "../../../context/auth";

export default function ViewUsers() {
  const authContext = React.useContext(AuthContext);

  let [data, setData] = React.useState([]);

  let [toggle, setToggle] = React.useState(false);

  async function toggleUserActivation(phone) {
    try {
      let res = await fetch(
        BACKEND + "/dashboard/user/toggleActivation/" + phone,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["token"],
          }),
        }
      );

      if (res.ok) {
        alert("Activation State CHANGED");
        setToggle(!toggle);
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  async function deleteUser(phone) {
    try {
      let res = await fetch(BACKEND + "/dashboard/user/delete/" + phone, {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["token"],
        }),
      });

      if (res.ok) {
        alert("USER DELETED");
        setToggle(!toggle);
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  async function getDataFromServer() {
    try {
      let res = await fetch(BACKEND + "/dashboard/user/view", {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["token"],
        }),
      });

      if (res.ok) {
        setData(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  function renderTable() {
    if (!data) {
      return null;
    }

    let result = data.map((user, index) => {
      return (
        <tr>
          <td>{index + 1}</td>
          <td>{user["name"]}</td>
          <td>{user["assigned_role"]}</td>

          <td>{user["phone"]}</td>
          <td>NA</td>
          <td>
            <div>
              <BootstrapSwitchButton
                style={{ width: "100%" }}
                checked={user["active"]}
                width={120}
                onstyle="success"
                offstyle="danger"
                onlabel="ACTIVE"
                offlabel="INACTIVE"
                onChange={(checked) => {
                  toggleUserActivation(user["phone"]);
                }}
              />
            </div>
          </td>
          <td>
            <Button
              variant="danger"
              onClick={() => {
                deleteUser(user["phone"]);
              }}
            >
              DELETE
            </Button>
          </td>
        </tr>
      );
    });

    return result;
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Administration</div>
              <h1 className={styles.title}>Existing Users</h1>
              <p className={styles.subtext}>
                Manage staff accounts from a responsive table with clear status controls.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>{data?.length || 0} accounts</span>
              <span className={styles.metaPill}>Status controls</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>User directory</Card.Header>
          <Card.Body className={styles.panelBody}>
            <div className={styles.tableShell}>
              <Table hover className="text-center align-middle mb-0">
                <thead>
                  <tr>
                    <th>S.No</th>
                    <th>Name</th>
                    <th>Role</th>
                    <th>Phone</th>
                    <th>District</th>
                    <th>Account Status</th>
                    <th>Delete</th>
                  </tr>
                </thead>
                <tbody>{renderTable()}</tbody>
              </Table>
            </div>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
