import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Alert, Form, Button, Table } from "react-bootstrap";

import { BACKEND } from "../../../CONSTANTS";

import { useNavigate } from "react-router-dom";
import AuthContext from "../../../context/auth";
export default function SearchMember() {
  const authContext = React.useContext(AuthContext);
  const NAVIGATE = useNavigate();

  let [searchData, setSearchData] = React.useState({
    attribute: "",
    value: "",
  });

  let [data, setData] = React.useState(null);

  async function GetDataFromServer() {
    try {
      if (!searchData["attribute"] || !searchData["value"]) {
        return;
      }

      let res = await fetch(BACKEND + "/dashboard/member/search", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
          "x-auth-token": authContext["user"]["token"],
        }),
        body: JSON.stringify(searchData),
      });

      if (res.ok) {
        setData(await res.json());
      } else alert("ERROR: " + (await res.text()));
    } catch (error) {
      alert("CLIENT ERROR: " + error.message);
    }
  }

  function renderTable() {
    if (data === null) {
      return null;
    }

    let temp = [];
    temp = data.map((member, index) => {
      return (
        <tr>
          <td>{index + 1}</td>
          <td>{member["name"]}</td>
          <td>{member["district"]}</td>
          <td>{member["constituency"]}</td>
          <td>{member["halqa"]}</td>
          <td>{member["phone"]}</td>

          <td>{member["status"]}</td>
          <td>
            <Button
              variant="success"
              onClick={(e) => {
                NAVIGATE(
                  "/dashboard/members/profile?id=" + member["member_id"]
                );
              }}
            >
              VIEW DETAILS
            </Button>
          </td>
        </tr>
      );
    });

    return temp;
  }
  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Member search</div>
              <h1 className={styles.title}>Search for Members</h1>
              <p className={styles.subtext}>
                Look up members by ID, phone number, or name from a cleaner, responsive interface.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>Quick lookup</span>
              <span className={styles.metaPill}>Responsive results</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Search filters</Card.Header>
          <Card.Body className={styles.panelBody}>
            <Form>
              <Row className="g-3 align-items-end">
                <Col md="4">
                  <Form.Label>Search attribute</Form.Label>
                  <Form.Select
                    value={searchData["attribute"]}
                    onChange={(e) => setSearchData({ ...searchData, attribute: e.target.value })}
                  >
                    <option value="">Please Choose</option>
                    <option value="member_id">Member ID</option>
                    <option value="phone">Phone Number</option>
                    <option value="name">Name</option>
                  </Form.Select>
                </Col>

                <Col md="5">
                  <Form.Label>Search text</Form.Label>
                  <Form.Control
                    value={searchData["value"]}
                    onChange={(e) => setSearchData({ ...searchData, value: e.target.value })}
                  />
                </Col>

                <Col md="3" className="d-flex justify-content-end">
                  <Button variant="dark" onClick={GetDataFromServer}>
                    Search
                  </Button>
                </Col>
              </Row>
            </Form>
          </Card.Body>
        </Card>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Search results</Card.Header>
          <Card.Body className={styles.panelBody}>
            <div className={styles.tableShell}>
              <Table hover className="text-center align-middle mb-0">
                <thead>
                  <tr>
                    <th>S.No</th>
                    <th>Name</th>
                    <th>District</th>
                    <th>Constituency</th>
                    <th>Halqa</th>
                    <th>Phone</th>
                    <th>Account Status</th>
                    <th>Member Profile</th>
                  </tr>
                </thead>
                <tbody>{renderTable()}</tbody>
              </Table>
            </div>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
