import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import screenStyles from "../../../Components/PageTemplate/DashboardScreen.module.css";
import styles from "./View.module.css";

import {
  Row,
  Col,
  Card,
  Button,
  Form,
} from "react-bootstrap";
import BootstrapSwitchButton from "bootstrap-switch-button-react";

import { BACKEND } from "../../../CONSTANTS";

import { useNavigate } from "react-router-dom";
import AuthContext from "../../../context/auth";

import useLocation from "../../../hooks/useLocation";

export default function ViewUsers() {
  const {
    renderConstituencyFromDistrict,
    renderHalqaFromConstituency,
    renderWardsFromConstituency,
  } = useLocation();

  const authContext = React.useContext(AuthContext);
  let [members, setMembers] = React.useState(null);
  let [toggle, setToggle] = React.useState(false);
  let [filter, setFilter] = React.useState({
    constituency: "",
    halqa: "",
    ward: "",
    filter_by: "NONE",
  });
  let [showFilters, setShowFilters] = React.useState(false);
  let [imageErrors, setImageErrors] = React.useState({});
  const NAVIGATE = useNavigate();

  function getInitials(name = "") {
    const words = String(name)
      .trim()
      .split(/\s+/)
      .filter(Boolean);
    if (words.length === 0) return "NA";
    if (words.length === 1) return words[0].slice(0, 2).toUpperCase();
    return `${words[0][0]}${words[1][0]}`.toUpperCase();
  }

  async function toggleUserActivation(phone) {
    try {
      let res = await fetch(
        BACKEND + "/dashboard/member/toggleActivation/" + phone,
        {
          method: "POST",
          headers: new Headers({
            "x-auth-token": authContext["user"]["token"],
          }),
        }
      );

      if (res.ok) {
        alert("Activation State CHANGED");
        setToggle(!toggle);
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  async function getDataFromServer() {
    try {
      console.log(filter);
      let res = await fetch(BACKEND + "/dashboard/member/view", {
        method: "POST",
        headers: new Headers({
          "x-auth-token": authContext["user"]["token"],
          "Content-Type": "application/json",
        }),
        body: JSON.stringify(filter),
        redirect: "follow",
      });

      if (res.ok) {
        setMembers(await res.json());
      }
    } catch (error) {
      alert("ERROR " + error.message);
    }
  }

  React.useEffect(() => {
    getDataFromServer();
  }, [toggle]);

  function renderCards() {
    if (members === null) {
      return <div className={styles.empty}>Loading members, please wait...</div>;
    }

    if (members.length === 0) {
      return <div className={styles.empty}>No members found for this filter.</div>;
    }

    let temp = members.map((member, index) => {
      return (
        <article key={member["member_id"]} className={styles.memberCard}>
          <div className={styles.memberHead}>
            <div className={styles.memberIdentity}>
              <div className={styles.memberAvatarWrap}>
                {imageErrors[member["member_id"]] ? (
                  <div className={styles.memberInitials}>
                    {getInitials(member["name"])}
                  </div>
                ) : (
                  <img
                    className={styles.memberAvatar}
                    src={`${BACKEND}/dashboard/member/image/${member["member_id"]}?token=${authContext["token"]}`}
                    alt={member["name"] || "member"}
                    onError={() => {
                      setImageErrors((prev) => ({
                        ...prev,
                        [member["member_id"]]: true,
                      }));
                    }}
                  />
                )}
              </div>

              <div className={styles.nameBlock}>
                <div className={styles.index}>Member #{index + 1}</div>
                <h3 className={styles.name}>{member["name"]}</h3>
                <div className={styles.subLine}>{member["constituency"] || "Constituency N/A"}</div>
              </div>
            </div>
            <span
              className={`${styles.statusBadge} ${
                member["status"] === "ACTIVE" ? styles.active : styles.inactive
              }`}
            >
              {member["status"]}
            </span>
          </div>

          <div className={styles.fieldGrid}>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>Parentage</span>
              <span className={styles.fieldValue}>{member["parentage"] || "N/A"}</span>
            </div>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>Phone</span>
              <span className={styles.fieldValue}>{member["phone"] || "N/A"}</span>
            </div>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>District</span>
              <span className={styles.fieldValue}>{member["district"] || "N/A"}</span>
            </div>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>Constituency</span>
              <span className={styles.fieldValue}>{member["constituency"] || "N/A"}</span>
            </div>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>Halqa</span>
              <span className={styles.fieldValue}>{member["halqa"] || "N/A"}</span>
            </div>
            <div className={styles.fieldItem}>
              <span className={styles.fieldLabel}>Ward</span>
              <span className={styles.fieldValue}>{member["ward"] || "N/A"}</span>
            </div>
          </div>

          <div className={styles.actions}>
            <div className={styles.toggleWrap}>
              <BootstrapSwitchButton
                checked={member["status"] === "ACTIVE"}
                width={150}
                onstyle="success"
                offstyle="danger"
                onlabel="ACTIVE"
                offlabel="INACTIVE"
                onChange={() => {
                  toggleUserActivation(member["phone"]);
                }}
              />
            </div>

            <Button
              variant="dark"
              className={styles.viewBtn}
              onClick={(e) => {
                NAVIGATE(
                  "/dashboard/members/profile?id=" + member["member_id"]
                );
              }}
            >
              View Details
            </Button>
          </div>
        </article>
      );
    });

    return temp;
  }

  return (
    <Template>
      <div className={screenStyles.page}>
        <section className={screenStyles.hero}>
          <div className={screenStyles.heroTop}>
            <div>
              <div className={screenStyles.eyebrow}>Member management</div>
              <h1 className={screenStyles.title}>Existing Members</h1>
              <p className={screenStyles.subtext}>
                Filter and manage members from a cleaner table view with easier mobile scanning.
              </p>
            </div>
            <div className={screenStyles.heroMeta}>
              <span className={screenStyles.metaPill}>{members?.length || 0} members</span>
              <span className={screenStyles.metaPill}>Activation controls</span>
            </div>
          </div>
        </section>

        <Card className={screenStyles.panel}>
          <Card.Header className={screenStyles.panelHeader}>Filter member data</Card.Header>
          <Card.Body className={screenStyles.panelBody}>
            <div className={styles.mobileFilterBar}>
              <Button
                variant="outline-secondary"
                size="sm"
                className={styles.mobileFilterToggle}
                onClick={() => setShowFilters(!showFilters)}
              >
                {showFilters ? "Hide Filters" : "Show Filters"}
              </Button>
            </div>

            <Row className={`g-3 ${styles.filterRow} ${showFilters ? styles.filterRowOpen : ""}`}>
              <Col md="3">
                <Form.Label>Constituency</Form.Label>
                <Form.Select
                  value={filter.constituency}
                  onChange={(e) => {
                    setFilter({
                      ...filter,
                      constituency: e.target.value,
                    });
                  }}
                >
                  <option value="">Please Choose</option>
                  {renderConstituencyFromDistrict("SRINAGAR").map((i) => {
                    return <option value={i}>{i}</option>;
                  })}
                </Form.Select>
              </Col>

              <Col md="3">
                <Form.Label>Halqa</Form.Label>
                <Form.Select
                  value={filter.halqa}
                  onChange={(e) => {
                    setFilter({
                      ...filter,
                      halqa: e.target.value,
                    });
                  }}
                >
                  <option value="">Please Choose</option>
                  {renderHalqaFromConstituency(filter.constituency).map((i) => {
                    return <option value={i}>{i}</option>;
                  })}
                </Form.Select>
              </Col>

              <Col md="3">
                <Form.Label>Ward</Form.Label>
                <Form.Select
                  value={filter.ward}
                  onChange={(e) => {
                    setFilter({
                      ...filter,
                      ward: e.target.value,
                    });
                  }}
                >
                  <option value="">Please Choose</option>
                  {renderWardsFromConstituency(filter.constituency).map((i) => {
                    return <option value={i}>{i}</option>;
                  })}
                </Form.Select>
              </Col>

              <Col md="3">
                <Form.Label>Filter by</Form.Label>
                <Form.Select
                  value={filter.filter_by}
                  onChange={(e) => {
                    setFilter({
                      ...filter,
                      filter_by: e.target.value,
                    });
                  }}
                >
                  <option value="">Please Choose</option>
                  <option value="NONE">None</option>
                  <option value="WARD">Ward</option>
                  <option value="HALQA">Halqa</option>
                </Form.Select>
              </Col>

              <Col xs="12" className={`d-flex justify-content-end ${styles.filterAction}`}>
                <Button
                  variant="dark"
                  onClick={() => {
                    getDataFromServer();
                    setShowFilters(false);
                  }}
                >
                  Apply Filter
                </Button>
              </Col>
            </Row>
          </Card.Body>
        </Card>

        <Card className={screenStyles.panel}>
          <Card.Header className={screenStyles.panelHeader}>Existing members</Card.Header>
          <Card.Body className={screenStyles.panelBody}>
            <div className={styles.memberGrid}>
              {renderCards()}
            </div>
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
