import React from "react";

import Template from "../../../Components/PageTemplate/Template";
import styles from "../../../Components/PageTemplate/DashboardScreen.module.css";

import { Row, Col, Card, Alert, Form, Button } from "react-bootstrap";
import { BACKEND } from "../../../CONSTANTS";
import AuthContext from "../../../context/auth";

export default function GenerateCard() {
  const authContext = React.useContext(AuthContext);
  let [searchData, setSearchData] = React.useState({
    attribute: "",
    value: "",
  });

  let [image, setImage] = React.useState(null);

  async function DownloadIDCard() {
    try {
      if (!searchData["attribute"] || !searchData["value"]) {
        return;
      }

      let res = await fetch(BACKEND + "/dashboard/member/generateIDCARD", {
        method: "POST",
        headers: new Headers({
          "Content-Type": "application/json",
          "x-auth-token": authContext["user"]["token"],
        }),
        body: JSON.stringify(searchData),
      });

      if (res.ok) {
        //
        let img_blob = await res.blob();
        let img_url = URL.createObjectURL(img_blob);
        setImage(img_url);
      } else alert("ERROR: " + (await res.text()));
    } catch (error) {
      alert("CLIENT ERROR: " + error.message);
    }
  }

  return (
    <Template>
      <div className={styles.page}>
        <section className={styles.hero}>
          <div className={styles.heroTop}>
            <div>
              <div className={styles.eyebrow}>Member tools</div>
              <h1 className={styles.title}>Generate ID Card</h1>
              <p className={styles.subtext}>
                Download a member card by searching with ID or phone from a streamlined layout.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.metaPill}>Printable output</span>
              <span className={styles.metaPill}>Responsive preview</span>
            </div>
          </div>
        </section>

        <Card className={styles.panel}>
          <Card.Header className={styles.panelHeader}>Card lookup</Card.Header>
          <Card.Body className={styles.panelBody}>
            <Form>
              <Row className="g-3 align-items-end">
                <Col md="4">
                  <Form.Label>Search attribute</Form.Label>
                  <Form.Select
                    value={searchData["attribute"]}
                    onChange={(e) => setSearchData({ ...searchData, attribute: e.target.value })}
                  >
                    <option value="">Please Choose</option>
                    <option value="member_id">Member ID</option>
                    <option value="phone">Phone Number</option>
                  </Form.Select>
                </Col>

                <Col md="5">
                  <Form.Label>Search text</Form.Label>
                  <Form.Control
                    value={searchData["value"]}
                    onChange={(e) => setSearchData({ ...searchData, value: e.target.value })}
                  />
                </Col>

                <Col md="3" className="d-flex justify-content-end">
                  <Button variant="dark" onClick={DownloadIDCard}>
                    Download I-Card
                  </Button>
                </Col>
              </Row>
            </Form>

            {image ? (
              <div className="mt-4 d-flex justify-content-center">
                <div className={styles.previewBox}>
                  <img src={image} alt="member card preview" style={{ maxWidth: "100%", borderRadius: "12px" }} />
                </div>
              </div>
            ) : null}
          </Card.Body>
        </Card>
      </div>
    </Template>
  );
}
